-- dbo.Adhoc_Banking_v source

CREATE VIEW [Adhoc_Banking_v] as  
select   
a.party_id as partyid,  
e.identifier_value as SocialInsuranceNumber 
from party a with (NOLOCK)  
left outer join party_identifier e with (NOLOCK) on a.party_id=e.party_id and e.is_deleted_ind='N'   
where a.is_deleted_ind='N' and e.identifier_value is not null and e.identifier_value !='' and e.identifier_typ_id=100001;


-- dbo.Adhoc_contact_addr_v source

CREATE VIEW [Adhoc_contact_addr_v] AS

select 
a.party_id as Partyid ,
a.party_typ_id,  
f.addr_typ_nm ,  
(f.addr_typ_nm +' '+ b.addr_id )as Address, 
pcm.contract_id as contractid, 

(case when  pcm.code_set_up_ind='R' then cast(pcm.region_cd as varchar)
      when  pcm.code_set_up_ind='B' then cast(pcm.branch_cd as varchar) 
      else pc.contract_cd end) selling_cd ,
b.party_addr_id,
b.addr_line1,
b.addr_line2,
b.addr_line3,
b.city, 
d.state_id, 
d.state_nm+'-'+d.state_cd as province,
b.other_state,
postal_cd, 
e.country_nm,
b.addr_id,
case when b.bad_addr_ind='Y' then 'Yes' else 'No' end 'bad_addr_ind',
case when b.addr_lock_ind='Y' then 'Yes' else 'No' end 'addr_lock_ind',
case when b.over_ride_ind='Y' then 'Yes' else 'No' end 'over_ride_ind',
case when c.party_role_id is not null and pc.contract_id is not null then  'Yes' else 'No' end 'assigned'

from 

party a WITH(NOLOCK)

left outer join party_addr b WITH(NOLOCK) on a.party_id=b.party_id  and b.is_deleted_ind='N'
left outer join party_contract_manu pcm WITH(NOLOCK) on a.party_id=pcm.party_id and pcm.is_set_up_cmpltd_ind='N' and  pcm.is_deleted_ind='N'
left outer join party_contract pc WITH(NOLOCK) on pcm.contract_id=pc.contract_id and pc.is_deleted_ind='N'
left outer join party_role_instance pr WITH(NOLOCK) on pr.role_instance_id=pc.party_role_id and pr.is_deleted_ind='N'
left outer join party_role_addr c WITH(NOLOCK) on b.party_addr_id=c.party_addr_id and pc.party_role_id=c.party_role_id and c.is_deleted_ind='N'
left outer join adm_state d on d.state_id=b.state_id and d.is_deleted_ind='N'
left outer join adm_country e on e.country_id=b.country_id and e.is_deleted_ind='N'
left outer join adm_addr_type f on b.addr_typ_id =f.addr_typ_id 

where a.is_deleted_ind='N';


-- dbo.Adhoc_license_v source

CREATE VIEW
    [dbo].[Adhoc_license_v]
    (
        partyid,
        e_o_ind,
        nrd_num,
        e_o_exp_dtm_lic,
        license_typ_nm,
        license_exp_dtm_lic,
        license_num,
        renewal_dt,
        full_license_ind,
        state_nm,
        lcnse_spnsr_comp_nm,
        sponsor_exp_dtm,
        name_on_license,
        name_on_license_clt,
        status,
        e_o_Insurer,
        issue_dtm,
        company_agency_nm,
        company_agency_nm_clt
    ) AS
    SELECT
    a.party_id AS partyid,
    CASE
        WHEN f.e_o_ind='Y'
        THEN 'Yes'
        WHEN f.e_o_ind='N'
        THEN 'No'
    END 'e_o_ind',
    f.nrd_num,
    f.e_o_exp_dtm AS e_o_exp_dtm_lic,
    c.license_typ_nm,
  a.license_exp_dtm AS license_exp_dtm_lic,
    case
    when license_num =''
    then NULL
    else license_num
    end 'license_num',
    a.renewal_dt AS renewal_dt,
    CASE
        WHEN full_license_ind='Y'
        THEN 'Yes'
        WHEN full_license_ind='N'
        THEN 'No'
    END 'full_license_ind',
    b.state_nm,
    CASE
        WHEN d.lcnse_spnsr_comp_nm = 'Manulife'
        THEN 'Yes'
        ELSE 'No'
    END lcnse_spnsr_comp_nm,
    a.sponsor_exp_dtm as sponsor_exp_dtm,
    case
    when a.name_on_license =''
    then NULL
    else a.name_on_license
    end 'name_on_license' ,
    case
    when a.name_on_license_clt =''
    then NULL
    else a.name_on_license_clt
    end 'name_on_license_clt' ,
    a.status,
    f.e_o_Insurer,
    a.issue_dtm as issue_dtm,
    case
    when a.company_agency_nm =''
    then NULL
    else a.company_agency_nm
    end 'company_agency_nm' ,
    case
    when a.company_agency_nm_clt =''
    then NULL
    else a.company_agency_nm_clt
    end 'company_agency_nm_clt'
FROM
    party_license_info a WITH (NOLOCK)
LEFT OUTER JOIN
    party f WITH (NOLOCK)
ON
    a.party_id=f.party_id
LEFT OUTER JOIN
    adm_state b
ON
    a.state_id=b.state_id
AND b.is_deleted_ind='N'
LEFT OUTER JOIN
    adm_license_type c
ON
    a.license_typ_id=c.license_typ_id
AND a.is_deleted_ind='N'
LEFT OUTER JOIN
    adm_party_lcnse_spnsr_comp d
ON
    d.lcnse_spnsr_comp_id=a.lcnse_spnsr_comp_id
AND d.is_deleted_ind='N'
WHERE
    a.is_deleted_ind='N';


-- dbo.Adhoc_relationship_v source

CREATE VIEW [Adhoc_relationship_v] as
select	a.party_id as partyid,	
		--dbo.fn_GetPartyName(a.party_id)FrParty_name,
		--b.party_b_role_id,
		--party_role_nm,
		(select party_role_nm from adm_party_role x where x.party_role_id=a.party_role_id)frparty_role_nm,
		d.contract_cd FrContract_cd,
		b.relationship_start_dt,
		b.relationship_end_dt,
		b.relationship_status,
		case when b.inheritable_ind='Y' then 'Yes' 
			 when b.inheritable_ind='N' then 'No' end 'inheritable_ind',
		c.party_id to_party_id,
		--dbo.fn_GetPartyName(c.party_id)ToParty_name,
		--b.party_a_role_id,
		(select party_role_nm from adm_party_role x where x.party_role_id=c.party_role_id)Toparty_role_nm,
		e.contract_cd ToContract_cd
from party_role_instance a with (NOLOCK) 
inner join party_relationship b with (NOLOCK) on a.role_instance_id=b.party_b_role_id  and b.is_deleted_ind='N'
inner join party_role_instance c with (NOLOCK) on b.party_a_role_id=c.role_instance_id and c.is_deleted_ind='N'
inner join party_contract d with (NOLOCK) on a.role_instance_id=d.party_role_id and d.is_deleted_ind='N'
inner join party_contract e with (NOLOCK) on c.role_instance_id=e.party_role_id and e.is_deleted_ind='N'
where b.is_deleted_ind='N';


-- dbo.CaseDetailsComments source

CREATE VIEW [CaseDetailsComments] as
SELECT     comments.comment_id, comments.cmnt_seq_num, comments.cmnt_cat_cd, 
                      comments.cmnt_typ_cd,
                          (SELECT    cmnt_typ_dsc
                            FROM          CMNT_TYPE WITH(NOLOCK) 
                            WHERE      cmnt_typ_cd = comments.cmnt_typ_cd) AS cmnt_typ_dsc, comments.cmnt_txt, comments.cmnt_sys_gen_ind, 
                      comments.cmnt_user_full_nm, CONVERT(varchar(10), comments.cmnt_cre_dt, 101) + ' ' + CONVERT(varchar(10), comments.cmnt_cre_dt, 108) 
                      AS cmnt_cre_dt,  document_type.doc_type_desc, case_cmnt.cpcli_id, 
                      case_cmnt.case_reqt_uni_id, case_cmnt.case_id , 
case when comments.cmnt_accs_typ_cd='p' then 'Private' 
when comments.cmnt_accs_typ_cd='L' then 'Public' 
when comments.cmnt_accs_typ_cd='s' then 'SemiPrivate'
end 'cmnt_accs_typ_cd'   , 
case when ((select count(*) from comments_attachments WITH(NOLOCK)  where comment_id = comments.comment_id) > 0) then 'Attachments'
when ((select count(*) from comments_attachments WITH(NOLOCK)  where comment_id = comments.comment_id) = 0) then ''
end  'Attachments' ,case_cmnt.lst_updt_user_id,
note_level.note_level_desc
FROM         comments WITH(NOLOCK)  INNER JOIN
                      case_cmnt WITH(NOLOCK) ON comments.comment_id = case_cmnt.comment_id  
					  LEFT OUTER JOIN 
					   note_level WITH(NOLOCK) ON comments.note_level_id=note_level.note_level_id	
  LEFT OUTER JOIN
                      document_type WITH(NOLOCK) ON comments.doc_type_id = document_type.doc_type_id;


-- dbo.Code_General source

CREATE VIEW [dbo].[Code_General] AS
select   
b.party_id as partyid,
b.contract_id as contractid,
c.contract_cd as selling_cd,
e.party_role_nm   as Party_role,
   (select channel from channel_view x WITH(NOLOCK) where x.channel_id=b.channel_id)channel_name,
       f.contract_status_nm as Code_Status ,
          --(select reason_nm from adm_reason x WITH(NOLOCK) where x.reason_id=b.status_change_reason_id) Status_Change_Reason,
			(select reason_nm from adm_Reason,adm_reason_typ_mapping where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
				and adm_reason_typ_mapping.reason_typ_map_id=b.status_change_reason_id ) Status_Change_Reason,
            c.contract_start_dtm as Contract_Effective_Date_cg,
            c.contract_end_dtm      as Contract_Termination_Date_cg,
        --(select reason_nm from adm_reason x WITH(NOLOCK) where x.reason_id=b.termination_reason_id)Termination_Reason,
		   (select reason_nm from adm_Reason,adm_reason_typ_mapping where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
				and adm_reason_typ_mapping.reason_typ_map_id=b.termination_reason_id ) Termination_Reason,
               b.branch_cd as Branch_code,
             (case when b.code_set_up_ind='I' then (select contract_type_nm  from party_contract x WITH(NOLOCK) inner join   adm_contract_type y WITH(NOLOCK) on  x.contract_id=c.parent_contract_id where x.contract_type_id=y.contract_type_id ) else null end) 'Branch_Contract_Type',
	(case when b.code_set_up_ind='I' then (select contract_type_cd  from party_contract x WITH(NOLOCK) inner join   adm_contract_type y WITH(NOLOCK) on  x.contract_id=c.parent_contract_id where x.contract_type_id=y.contract_type_id ) else null end) 'Branch_Contract_Cd',
           (case when b.code_set_up_ind='I' then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'') from party_contract_manu x WITH(NOLOCK) inner join party y WITH(NOLOCK)on x.party_id=y.party_id where x.contract_id=c.parent_contract_id) else null end)Branch,
            b.ident     as Ident,
            g.contract_type_cd      as Contract_type_nm,
            g.contract_type_nm      as Contract_type_cd,  
(select contract_type_nm from adm_contract_type x WITH(NOLOCK) where x.contract_type_id=b.reporting_cont_contract_type_id)Reporting_Controller_Contract_Type,
           (select contract_type_cd from adm_contract_type x WITH(NOLOCK) where x.contract_type_id=b.reporting_cont_contract_type_id)Reporting_Controller_Contract_Type_DESC,
    
            (select code_set_up_ind from party_contract_manu x WITH(NOLOCK) where x.contract_id=b.reporting_cont_cd)code_setup_ind,

      (case  when (select code_set_up_ind from party_contract_manu x WITH(NOLOCK) where x.contract_id=b.reporting_cont_cd)='B' 
                        then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'')  from party_contract_manu x WITH(NOLOCK) inner join party y WITH(NOLOCK) on x.party_id=y.party_id where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='B' )                         
                    else (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'')  from party_contract_manu x WITH(NOLOCK) inner join party_contract z WITH(NOLOCK) on x.contract_id=z.contract_id inner join party y WITH(NOLOCK) on x.party_id=y.party_id where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='I' ) 
                    end)Reporting_Controller_Code_DESC,
(case   when (select code_set_up_ind from party_contract_manu x WITH(NOLOCK) where x.contract_id=b.reporting_cont_cd)='B' 
                        then (select top 1 cast(x.branch_cd as varchar)  from party_contract_manu x WITH(NOLOCK) where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='B' )                         
                    else (select top 1 cast(z.contract_cd as varchar)  from party_contract_manu x WITH(NOLOCK) inner join party_contract z WITH(NOLOCK) on x.contract_id=z.contract_id  where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='I' ) 
                    end)Reporting_Controller_Code_TYPE,
            --i.reason_nm as Reporting_Controller_Change_Reason,
		(select reason_nm from adm_reason where reason_id=i.reason_id) Reporting_Controller_Change_Reason,
--        (select contract_cd from party_contract WITH(NOLOCK) where contract_id= b.payment_cont_cd)as Payment_Controller_Code,            
            --h.reason_nm as Payment_Controller_Change_Reason,
--			(select reason_nm from adm_reason where reason_id=h.reason_id) Payment_Controller_Change_Reason,
            msc.legacy_code Maritime_Selling_Code,
            wc.legacy_code Wealth_Code,
            msrc.legacy_code Manulife_Securities_Code,
            msdc.legacy_code Manulife_Securities_D_Code,
            msqc.legacy_code Manulife_Securities_Q_Code,
(select tax_indicator from adm_tax_indicator x WITH(NOLOCK) where x.tax_indicator_id=b.tax_ind_id)Tax_Indicator,
acv.contract_version_nm 'Contract_version'

from party_role_instance a WITH(NOLOCK)
inner join party_contract_manu            b WITH(NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N' and b.is_set_up_cmpltd_ind='N' 
inner join party_contract                 c WITH(NOLOCK) on b.contract_id=c.contract_id and a.role_instance_id=c.party_role_id and c.is_deleted_ind='N'
left outer join adm_party_role       e on a.party_role_id=e.party_role_id and e.is_deleted_ind='N'
left outer join adm_contract_status  f  on c.contract_status_id=f.contract_status_id and f.is_deleted_ind='N'
left outer join adm_contract_type    g  on c.contract_type_id=g.contract_type_id and g.is_deleted_ind='N'
--left outer join adm_reason_typ_mapping   h  on h.reason_typ_map_id=b.payment_cont_change_reason_id and h.is_deleted_ind='N'
left outer join adm_reason_typ_mapping i on b.reporting_cont_change_reason_id=i.reason_typ_map_id and i.is_deleted_ind='N'
--left outer join contract_legacy_code j WITH(NOLOCK) on b.contract_id=j.contract_id and j.attribute_id in (100014,100010,100011,100012,100013) and j.is_deleted_ind='N'

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100014 and is_deleted_ind='N') msc on
msc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100010 and is_deleted_ind='N') wc on
wc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100011 and is_deleted_ind='N') msrc on
msrc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100012 and is_deleted_ind='N') msdc on
msdc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100013 and is_deleted_ind='N') msqc on
msqc.contract_id=c.contract_id

left outer join adm_contract_version acv on acv.contract_version_id = b.contract_version_id and acv.is_deleted_ind='N'

where b.code_set_up_ind in ('I') and a.is_deleted_ind='N';


-- dbo.Codes source

CREATE VIEW  [dbo].[Codes] as
select 
a.party_id    as partyid,
a.contract_id as contractid,
d.code_typ as codetype,
b.code_value as code,
case when d.statusConfig='Y' or d.statusConfig='N' then 
				(select other_cd_status from adm_other_cd_status where other_cd_status_id=b.code_status)
     else coalesce (c.contract_status_nm,'') end as status,
coalesce (b.other_branch_cd,'') as branchcode
from party_contract_manu a with (NOLOCK) 
inner join contract_other_code  b with (NOLOCK) on a.contract_id=b.contract_id and b.is_deleted_ind='N'
left outer join adm_contract_status c on b.code_status=c.contract_status_id  and c.is_deleted_ind='N'
left outer join adm_code_type d on b.code_typ_id = d.code_typ_id  and d.is_deleted_ind='N'
where  a.is_deleted_ind='N' and  a.is_set_up_cmpltd_ind='N';


-- dbo.Contract_Codes source

CREATE VIEW [Contract_Codes] as
SELECT    party.party_id, adm_party_type.party_typ_id,adm_party_type.party_typ_nm, party.first_nm, party.last_nm, party.middle_nm, 
           (case when party.party_typ_id=100002 then party.last_nm else null end)org_nm,
			--party_name.org_nm, 
            party_contract.contract_cd, adm_code_type.code_typ_id,adm_code_type.code_typ, contract_other_code.code_value, 
           contract_other_code.code_status, contract_other_code.other_branch_cd,adm_code_status.code_status_nm,party_contract.contract_id
FROM       party with (NOLOCK) INNER JOIN
		   adm_party_type ON adm_party_type.party_typ_id = party.party_typ_id INNER JOIN
           --party_name ON party.party_id = party_name.party_id INNER JOIN
           party_role_instance with (NOLOCK) ON party.party_id = party_role_instance.party_id inner JOIN
           party_contract with (NOLOCK) ON party_role_instance.role_instance_id = party_contract.party_role_id inner JOIN
           contract_other_code with (NOLOCK) on party_contract.contract_id = contract_other_code.contract_id  and contract_other_code.is_deleted_ind = 'N' left join
           adm_code_status on contract_other_code.code_status  =  adm_code_status.code_status_id left join 
		   adm_code_type ON adm_code_type.code_typ_id = contract_other_code.code_typ_id;


-- dbo.Contract_flags source

CREATE VIEW [Contract_flags] as
SELECT     party.party_id, adm_party_type.party_typ_id, adm_party_type.party_typ_nm, party.first_nm, party.last_nm, party.middle_nm, 
                      (case when party.party_typ_id=100002 then party.last_nm else null end)org_nm,
					--party_name.org_nm, 
                      party_role_instance.party_role_id, party_contract.contract_id, party_contract.contract_cd, adm_attribute.attribute_nm, 
                      adm_attribute.attribute_id, contract_legacy_code.legacy_code
FROM         party with (NOLOCK) INNER JOIN
                      adm_party_type ON party.party_typ_id = adm_party_type.party_typ_id INNER JOIN
                      --party_name ON party.party_id = party_name.party_id INNER JOIN
                      party_role_instance with (NOLOCK) ON party.party_id = party_role_instance.party_id INNER JOIN
                      party_contract with (NOLOCK) ON party_role_instance.role_instance_id = party_contract.party_role_id INNER JOIN
                      contract_legacy_code with (NOLOCK) ON party_contract.contract_id = contract_legacy_code.contract_id and 
					  contract_legacy_code.is_deleted_ind = 'N' INNER JOIN
                      adm_attribute ON contract_legacy_code.attribute_id = adm_attribute.attribute_id;


-- dbo.DEMADMINVIEW source

CREATE VIEW [DEMADMINVIEW]
AS
SELECT     BOM_BOID EntityId,BOM_NAME [Name],BOM_DISPLAYNAME EntityDisplayName,BOM_DEFAULTLOCALEID DefaultLocaleId,
BOM_DEFAULTLANGUAGEID DefaultLanguageId, BOM_TABLENAME TableName,BOM_MULTIATTRIBUTE_TABLENAME ChildTableName, 
BOM_ISSYSTEM IsSystem,BOM_ISSOFTDELETEREQUIRED SoftDeleteRequired, BOM_COMPLETEVIEWNAME CompleteViewName,
BOM_DESCRIPTION [Description] ,BOM_ISCREATE IsCreate,BOM_DATASOURCEID DataSource,BOM_ISDIRTY IsDirty,                       
BOM_ISDELETED EntityIsDelete,BOM_CONCURRENCYNUMBER EntityConcurrencyNo,
BAT_ATTRIBUTENAME AttributeName, BAT_ATTRIBUTEDISPLAYNAME AttributeDisplayName, 
BAT_MAX_OCCURENCES MaxOccurences, BAT_MIN_OCCURENCES MinOccurences,BAT_DATALENGTH [DataLength],  
BAT_DEFAULTVALUE DefaultValue,BAT_FORMFIELDTYPEID FormFieldTypeId,BAT_ISSEARCHABLE IsSearchable, 
DATATYPE AttributeDataType,BAT_ISUNIQUE IsUnique,BAT_ISVISIBLE IsVisible,
BAT_ISENCRYPTED IsEncrypted,BAT_DATAENTRYSTYLE DataEntryStyle,BOV_VIEWNAME ViewName, BOV_ISACTIVE IsActive,
BOV_ISDELETED IsDeleted,BOR_RELATIONSHIPID RelationshipId,BOR_RELATIONSHIPNAME RelationshipName,
--BOR_BOID1 ParentObject,
(SELECT BOM_NAME FROM BOMASTER X WHERE X.BOM_BOID=BORELATIONSHIP.BOR_BOID1)ParentObject, 
--BOR_BOID2 ChildObject,
(SELECT BOM_NAME FROM BOMASTER X WHERE X.BOM_BOID=BORELATIONSHIP.BOR_BOID2)ChildObject, 
BOR_ATTRIBUTENAME ChildAttribute,BOR_ISCASCADEDELETE CascadeDelete
FROM         BOMASTER
LEFT OUTER JOIN BOATTRIBUTE ON BOATTRIBUTE.BAT_BOID=BOMASTER.BOM_BOID
LEFT OUTER JOIN BOVIEW ON BOVIEW.BOV_BOID=BOATTRIBUTE.BAT_BOID AND BOVIEW.BOV_BOID=BOMASTER.BOM_BOID
LEFT OUTER JOIN BORELATIONSHIP ON BORELATIONSHIP.BOR_BOID1=BOVIEW.BOV_BOID 
LEFT OUTER JOIN TBL_DATATYPES ON TBL_DATATYPES.DATATYPEID= BOATTRIBUTE.BAT_ATTRIBUTEDATATYPEID;


-- dbo.EmailFaxHistory source

CREATE VIEW [EmailFaxHistory] AS
select ctypeid,Communication_status, Date_time, Sent_to, sent_from,subject, Communicationtype, case_id, linkid, Attachment from 
((select e.email_id ctypeid, es.description Communication_status,
convert(varchar,eh.email_sent_date,101)+ ' ' + convert(varchar,eh.email_sent_date,108) Date_Time,
e.email_to Sent_To,
(select lastname+' '+firstname from users where userid = e.lst_updt_userid) Sent_from,email_subject subject,'Email' Communicationtype, erh.case_id, cast(e.email_id as varchar) + '_Email' linkid,
 case when (select count(*) from email_attachment where email_attachment.email_id = e.email_id) = 0 then ''
     when (select count(*)  from email_attachment where email_attachment.email_id = e.email_id) = 1 then '1 Attachment'
     when (select count(*) from email_attachment where email_attachment.email_id = e.email_id) > 1 then 
convert(varchar,(select count(*) from email_attachment where email_attachment.email_id = e.email_id))+' Attachments'
End as Attachment from email_history eh,email_status es,email e,email_relation_history erh
where e.email_id=eh.email_id and e.email_id = erh.email_id
and eh.email_status_id=es.email_status_id) 
UNION 
(select f.fax_id ctypeid, fs.description Communication_Status,convert(varchar,fh.fax_sent_date,101)+ ' ' + convert(varchar,fh.fax_sent_date,108),
f.fax_num,(select lastname+' '+firstname from users where userid = f.lst_updt_userid),fax_subject subject,'Fax' Communicationtype,frh.case_id,cast(f.fax_id as varchar)+'_Fax' linkid,
case when (select count(*) from fax_attachment where fax_attachment.fax_id = f.fax_id) = 0 then ''
     when (select count(*) from fax_attachment where fax_attachment.fax_id = f.fax_id) = 1 then '1 Attachment'
     when (select count(*) from fax_attachment where fax_attachment.fax_id = f.fax_id) > 1 then convert(varchar,(select count(*) from fax_attachment where fax_attachment.fax_id = f.fax_id))+' Attachments'
End as Attachment from fax_history fh,fax_status fs,fax f ,fax_relation_history frh
where f.fax_id=fh.fax_id and fh.fax_status_id=fs.fax_status_id
and f.fax_id =frh.fax_id ))A;


-- dbo.FormTemplateHistory source

CREATE VIEW [FormTemplateHistory] AS
SELECT  form_template_list.form_nm, form_history.create_dtm, form_template_list.form_id, 
form_history.form_history_id, form_history.case_id, users.lastname + ', ' + users.firstname AS created_user 
FROM form_history INNER JOIN form_template_list ON form_history.form_id = form_template_list.form_id 
INNER JOIN users ON form_history.lst_updt_userid = users.userid;


-- dbo.GENERAL_INFO_CORP source

CREATE VIEW [GENERAL_INFO_CORP] as
SELECT     party.death_dt, party_identifier.identifier_value, party_other_name.other_nm, party.last_nm
FROM         party with (NOLOCK) INNER JOIN
                      --party_name ON party.is_deleted_ind = 'N' and party.party_id = party_name.party_id and party_name.is_deleted_ind = 'N' INNER JOIN
                      party_other_name with (NOLOCK) ON party.party_id = party_other_name.party_id and party_other_name.is_deleted_ind = 'N'INNER JOIN
                      party_identifier with (NOLOCK) ON party.party_id = party_identifier.party_id and 
					  party_identifier.identifier_typ_id = '100003' and party_identifier.is_deleted_ind = 'N' and party.is_deleted_ind = 'N';


-- dbo.GLOBAL_SEARCH_view source

CREATE VIEW [GLOBAL_SEARCH_view] as
select a.party_id,
a.party_typ_id,
b.party_role_id,
a.last_nm ,a.first_nm,
f.channel_id,
cv.channel_desc as channel_desc,
f.branch_cd, 
--(case when f.branch_cd is not null then (case when a.party_typ_id=100002 then c.org_nm 
--  when a.party_typ_id=100001 then 
--coalesce(c.last_nm,'')+' '+ coalesce(c.first_nm,'')+' '+coalesce(c.middle_nm,'') else null end)end) as branch_name, 
(case when f.branch_cd is not null then 
      coalesce(a.last_nm,'')+' '+ coalesce(a.first_nm,'')+' '+
          coalesce(a.middle_nm,'')end) as branch_name, 
f.contract_id, g.contract_cd,
h.code_value, j.contract_status_nm,
l.contract_type_cd+'-'+l.contract_type_nm as contracttype,
f.ident,h.code_typ_id, CAST(h.code_value as varchar(100)) + '-' + CAST(i.code_typ as varchar(100)) as other_code_value, 
d.addr_line1, d.addr_line2, d.city, e.state_id, 
e.state_nm+'-'+e.state_cd as province, d.postal_cd, m.country_nm
from party a with (NOLOCK) 
left outer join party_role b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N' 
left outer join  adm_party_role k on k.party_role_id=b.party_role_id and k.is_deleted_ind='N' 
--inner join party_name c on a.party_id=c.party_id and c.is_deleted_ind='N' 
--left outer join adm_party_status j on j.party_status_id=a.party_status_id and j.is_deleted_ind='N' 
left outer join party_contract_manu f with (NOLOCK) on a.party_id=f.party_id and f.is_deleted_ind='N' and f.is_set_up_cmpltd_ind='N'
left outer join party_contract g with (NOLOCK) on f.contract_id=g.contract_id and g.is_deleted_ind='N' 
left outer join adm_contract_status j on j.contract_status_id=g.contract_status_id and j.is_deleted_ind='N' 
left outer join party_addr d with (NOLOCK) on a.party_id=d.party_id and d.is_deleted_ind='N'
left outer join adm_state e on d.state_id=e.state_id and e.is_deleted_ind='N'
left outer join contract_other_code h with (NOLOCK) on f.contract_id= h.contract_id and h.is_deleted_ind='N' 
left outer join adm_code_type i on h.code_typ_id=i.code_typ_id and i.is_deleted_ind='N' 
left outer join adm_contract_type l on g.contract_type_id=l.contract_type_id and l.is_deleted_ind='N'
left outer join adm_country m on m.country_id=d.country_id and m.is_deleted_ind='N'
left outer join channel_view cv on cv.channel_id=f.channel_id
where a.is_deleted_ind='N';


-- dbo.General_Info source

CREATE VIEW [General_Info] as  
SELECT     a.party_id AS partyid, i.party_typ_nm, e.salutation_nm AS Salutaion, a.first_nm AS First_Name, a.middle_nm AS Middle_Name, 
                      a.last_nm AS Last_Name,
                          (SELECT     other_nm
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100003)) AS Reporting_first_Name,
                          (SELECT     other_nm
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100004)) AS Reporting_Middle_Name,
                          (SELECT     other_nm
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id IN (100001, 100005))) AS Reporting_Last_Name, dbo.fn_GetChequeName(a.party_id) 
                      AS Cheque_Name, f.gender_nm AS gender, g.marital_status_nm AS Marital_Status, a.nick_nm AS Nick_Name, a.dob AS Date_Of_Birth, 
                      dbo.fn_GetDesgNameList(a.party_id) AS Designation, 
                      CASE WHEN a.party_typ_id = 100001 THEN (CASE WHEN a.deceased_ind = 'Y' THEN 'Yes' WHEN a.deceased_ind = 'N' THEN 'No' END) 
                      ELSE '' END AS Deceased_Indicator, 
                      CASE WHEN a.party_typ_id = 100002 THEN (CASE WHEN a.deceased_ind = 'Y' THEN 'Yes' WHEN a.deceased_ind = 'N' THEN 'No' END) 
                      ELSE '' END AS Dissolution_Indicator, a.last_nm AS Company_Name,
                          (SELECT     other_nm
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100001)) AS Reporting_Company_Name, a.death_dt AS party_death_dt, j.identifier_value, 
                      a.title, a.first_nm_clt AS First_Name_clt, a.last_nm_clt AS Last_Name_clt, a.middle_nm_clt AS Middle_Name_clt, a.nick_nm_clt AS Nick_Name_clt,
                          (SELECT     other_nm_clt
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100003)) AS Reporting_first_Name_clt,
                          (SELECT     other_nm_clt
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100004)) AS Reporting_Middle_Name_clt,
                          (SELECT     other_nm_clt
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id IN (100001, 100005))) AS Reporting_Last_Name_clt,
                          (SELECT     other_nm_clt
                            FROM          dbo.party_other_name AS x WITH (NOLOCK)
                            WHERE      (party_id = a.party_id) AND (other_nm_typ_id = 100002)) AS Cheque_Name_clt, l.regulatory_cat_nm AS Regulatory_Category,
(select firm_type_nm from adm_party_firm_type where adm_party_firm_type.firm_type_id=m.identifier_value) firm_type_nm,
n.identifier_value gst_hst_value,
replace(n.identifier_value,' ','') gst_hst_value_clt,
apexaId.identifier_value as apexa_id,
bin.identifier_value as business_no,
qbin.identifier_value as q_business_no,
a.legal_business_name,
a.mothers_maiden_nm 
FROM         dbo.party AS a WITH (NOLOCK) LEFT OUTER JOIN
                      dbo.adm_salutation AS e ON a.salutation_id = e.salutation_id AND e.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.adm_gender AS f ON a.gender_id = f.gender_id AND f.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.adm_marital_status AS g ON a.marital_status_id = g.marital_status_id AND g.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.adm_party_type AS i ON a.party_typ_id = i.party_typ_id AND i.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.party_identifier AS j WITH (NOLOCK) ON a.party_id = j.party_id AND j.identifier_typ_id = 100002 AND j.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.party_identifier AS k WITH (NOLOCK) ON a.party_id = k.party_id AND k.identifier_typ_id = 100005 AND k.is_deleted_ind = 'N' LEFT OUTER JOIN
                      dbo.adm_regulatory_category AS l ON l.regulatory_cat_id = k.identifier_value AND k.is_deleted_ind = 'N' 
					  LEFT OUTER JOIN party_identifier m WITH(NOLOCK) on a.party_id=m.party_id and m.identifier_typ_id=100007 and m.is_deleted_ind='N'
					  LEFT OUTER JOIN party_identifier n WITH(NOLOCK) on a.party_id=n.party_id and n.identifier_typ_id=100006 and n.is_deleted_ind='N'
					  LEFT OUTER JOIN party_identifier apexaId WITH(NOLOCK) on a.party_id=apexaId.party_id and apexaId.identifier_typ_id=100010 and apexaId.is_deleted_ind='N'
					  LEFT OUTER JOIN party_identifier bin WITH(NOLOCK) on a.party_id=bin.party_id and bin.identifier_typ_id=100009 and bin.is_deleted_ind='N'
					  LEFT OUTER JOIN party_identifier qbin WITH(NOLOCK) on a.party_id=qbin.party_id and qbin.identifier_typ_id=100011 and qbin.is_deleted_ind='N'
WHERE a.is_deleted_ind='N';


-- dbo.MLIShareService_dependence_on_non_con_relationship_View source

CREATE VIEW [dbo].[MLIShareService_dependence_on_non_con_relationship_View]
AS
SELECT     pri.party_id, pcma.channel_id from_Channel, pcmb.channel_id to_Channel, cast(prn.relationship_id AS varchar) relationship_id,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party WITH (nolock)
                            WHERE      party.party_id = prn.from_party_id) AS frompartyname,
                          (SELECT     adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (nolock) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      party_role_instance.role_instance_id = prn.party_a_role_id AND party_role_instance.party_id = pri.party_id) AS frompartyrole, 
                      prn.party_lvl_from_ind AS from_lvl_ind, 
                      (CASE WHEN pcma.code_set_up_ind = 'I' THEN pca.contract_cd WHEN pcma.code_set_up_ind = 'B' THEN cast(pcma.branch_cd AS varchar) 
                      WHEN pcma.code_set_up_ind = 'R' THEN cast(pcma.region_cd AS varchar) END) AS FROM_CODE, 
                      (CASE WHEN pcmb.code_set_up_ind = 'I' THEN pcb.contract_cd WHEN pcmb.code_set_up_ind = 'B' THEN cast(pcmb.branch_cd AS varchar) 
                      WHEN pcmb.code_set_up_ind = 'R' THEN cast(pcmb.region_cd AS varchar) END) AS TO_CODE, prn.to_party_id AS topartyid,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party WITH (NOLOCK)
                            WHERE      party.party_id = prn.to_party_id) AS topartyname,
                          (SELECT     adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (NOLOCK) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      party_role_instance.role_instance_id = prn.party_b_role_id AND prn.to_party_id = party_role_instance.party_id) AS topartyrole,
                          (SELECT     party_role_instance.party_role_id
                            FROM          party_role_instance
                            WHERE      party_role_instance.role_instance_id = prn.party_b_role_id AND prn.to_party_id = party_role_instance.party_id) AS topartyroleid,
                          (SELECT     title
                            FROM          party p
                            WHERE      p.party_id = prn.to_party_id AND is_deleted_ind = 'N') AS title, prn.party_lvl_to_ind AS to_lvl_ind, prn.relationship_status, prn.rel_status_id, NULL 
                      AS inhrdfrompartyid, NULL AS inhrdfrompartyname,
                          (SELECT    COALESCE (party.first_nm, '') 
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_first_name,
                          (SELECT     COALESCE (party.last_nm, '')
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_last_name
FROM         party_relationship_ncr prn WITH (NOLOCK) INNER JOIN
                      party_role_instance pri WITH (NOLOCK) ON prn.party_a_role_id = pri.role_instance_id AND pri.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract pca WITH (NOLOCK) ON pca.party_role_id = prn.party_a_role_id AND pca.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcma WITH (NOLOCK) ON pcma.contract_id = pca.contract_id AND pcma.is_deleted_ind = 'N' AND 
                      pcma.is_set_up_cmpltd_ind = 'N' LEFT OUTER JOIN
                      party_contract pcb WITH (NOLOCK) ON pcb.party_role_id = prn.party_b_role_id AND pcb.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcmb WITH (NOLOCK) ON pcmb.contract_id = pcb.contract_id AND pcmb.is_deleted_ind = 'N' AND pcmb.is_set_up_cmpltd_ind = 'N'
WHERE     prn.is_deleted_ind = 'N'
UNION
SELECT     pcm.party_id, pcm.channel_id from_Channel, pcmb.channel_id to_Channel, cast(prn.relationship_id AS varchar) + 'I' + cast(pri.role_instance_id AS varchar) 
                      relationship_id,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party
                            WHERE      party.party_id = pcm.party_id) AS frompartynm,
                          (SELECT     adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (nolock) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      party_role_instance.role_instance_id = pri.role_instance_id AND party_role_instance.party_id = pcm.party_id) AS frompartyrole, NULL AS from_lvl_ind, 
                      (CASE WHEN pcma.code_set_up_ind = 'I' THEN pca.contract_cd WHEN pcma.code_set_up_ind = 'B' THEN cast(pcma.branch_cd AS varchar) 
                      WHEN pcma.code_set_up_ind = 'R' THEN cast(pcma.region_cd AS varchar) END) AS FROM_CODE, 
                      (CASE WHEN pcmb.code_set_up_ind = 'I' THEN pcb.contract_cd WHEN pcmb.code_set_up_ind = 'B' THEN cast(pcmb.branch_cd AS varchar) 
                      WHEN pcmb.code_set_up_ind = 'R' THEN cast(pcmb.region_cd AS varchar) END) AS TO_CODE, prn.to_party_id AS topartyid,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party WITH (nolock)
                            WHERE      party.party_id = prn.to_party_id) AS topartyname,
                          (SELECT     adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (nolock) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      party_role_instance.role_instance_id = prn.party_b_role_id AND prn.to_party_id = party_role_instance.party_id) AS topartyrole,
                          (SELECT     party_role_instance.party_role_id
                            FROM          party_role_instance
                            WHERE      party_role_instance.role_instance_id = prn.party_b_role_id AND prn.to_party_id = party_role_instance.party_id) AS topartyroleid,
                          (SELECT     title
                            FROM          party p
                            WHERE      p.party_id = prn.to_party_id AND is_deleted_ind = 'N') AS title, NULL AS to_lvl_ind, prn.relationship_status, prn.rel_status_id, 
                      prn.from_party_id AS inhrdfrompartyid,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '')
                            FROM          party
                            WHERE      party_id = prn.from_party_id) AS inhrdfrompartyname,
                           (SELECT    COALESCE (party.first_nm, '') 
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_first_name,
                          (SELECT     COALESCE (party.last_nm, '')
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_last_name
FROM         party_contract_manu pcm WITH (NOLOCK) INNER JOIN
                      party_contract pc WITH (NOLOCK) ON pc.contract_id = pcm.contract_id AND pc.is_deleted_ind = 'N' INNER JOIN
                      parent_role_instances pri WITH (NOLOCK) ON pri.role_instance_id = pc.party_role_id INNER JOIN
                      party_relationship_ncr prn WITH (NOLOCK) ON prn.party_a_role_id = pri.parent_role_instance_id AND prn.inheritable_ind = 'Y' AND 
                      prn.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract pca WITH (NOLOCK) ON pca.party_role_id = pri.role_instance_id AND pca.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcma WITH (NOLOCK) ON pcma.contract_id = pca.contract_id AND pcma.is_deleted_ind = 'N' AND 
                      pcma.is_set_up_cmpltd_ind = 'N' LEFT OUTER JOIN
                      party_contract pcb WITH (NOLOCK) ON pcb.party_role_id = prn.party_b_role_id AND pcb.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcmb WITH (NOLOCK) ON pcmb.contract_id = pcb.contract_id AND pcmb.is_deleted_ind = 'N' AND pcmb.is_set_up_cmpltd_ind = 'N'
WHERE     pcm.is_deleted_ind = 'N' AND pcm.is_set_up_cmpltd_ind = 'N'
UNION
SELECT     prn.from_party_id party_id, pcma.channel_id from_Channel, pcmb.channel_id to_Channel, cast(prn.relationship_id AS varchar) 
                      + 'I' + cast(pri.role_instance_id AS varchar) + 'B' relationship_id,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party WITH (nolock)
                            WHERE      party.party_id = prn.from_party_id) AS frompartynm,
                          (SELECT     adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (NOLOCK) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      party_role_instance.role_instance_id = prn.party_a_role_id AND party_role_instance.party_id = prn.from_party_id) AS frompartyrole, NULL 
                      AS from_lvl_ind, (CASE WHEN pcma.code_set_up_ind = 'I' THEN pca.contract_cd WHEN pcma.code_set_up_ind = 'B' THEN cast(pcma.branch_cd AS varchar) 
                      WHEN pcma.code_set_up_ind = 'R' THEN cast(pcma.region_cd AS varchar) END) AS FROM_CODE, 
                      (CASE WHEN pcmb.code_set_up_ind = 'I' THEN pcb.contract_cd WHEN pcmb.code_set_up_ind = 'B' THEN cast(pcmb.branch_cd AS varchar) 
                      WHEN pcmb.code_set_up_ind = 'R' THEN cast(pcmb.region_cd AS varchar) END) AS TO_CODE,
                          (SELECT     party_id
                            FROM          party_role_instance pr
                            WHERE      pr.role_instance_id = pri.role_instance_id) AS topartyid,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '') AS frompartyname
                            FROM          party WITH (NOLOCK) INNER JOIN
                                                   party_role_instance WITH (nolock) ON party_role_instance.role_instance_id = pri.role_instance_id
                            WHERE      party.party_id = party_role_instance.party_id) AS topartyname,
                          (SELECT     TOP (1) adm_party_role.party_role_nm
                            FROM          party_role_instance WITH (NOLOCK) INNER JOIN
                                                   adm_party_role ON party_role_instance.party_role_id = adm_party_role.party_role_id
                            WHERE      (party_role_instance.role_instance_id = pri.role_instance_id)) AS topartyrole,
      (SELECT     party_role_instance.party_role_id
                            FROM          party_role_instance
                            WHERE      party_role_instance.role_instance_id = prn.party_b_role_id AND prn.to_party_id = party_role_instance.party_id) AS topartyroleid,
                          (SELECT     title
                            FROM          party p
                            WHERE      p.party_id =
                                                       (SELECT     party_id
                                                         FROM          party_role_instance pr
                                                         WHERE      pr.role_instance_id = pri.role_instance_id AND is_deleted_ind = 'N') AND is_deleted_ind = 'N') AS title, NULL AS to_lvl_ind, 
                      prn.relationship_status, prn.rel_status_id, prn.to_party_id AS inhrdfrompartyid,
                          (SELECT     COALESCE (party.last_nm, '') + ' ' + COALESCE (party.first_nm, '') + ' ' + COALESCE (party.middle_nm, '')
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS inhrdfrompartyname,
                           (SELECT    COALESCE (party.first_nm, '') 
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_first_name,
                          (SELECT     COALESCE (party.last_nm, '')
                            FROM          party
                            WHERE      party_id = prn.to_party_id) AS to_party_last_name
FROM         party_relationship_ncr prn WITH (NOLOCK) INNER JOIN
                      party_contract pc WITH (NOLOCK) ON pc.party_role_id = prn.party_b_role_id AND pc.is_deleted_ind = 'N' INNER JOIN
                      party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = pc.contract_id AND pcm.is_deleted_ind = 'N' AND is_set_up_cmpltd_ind = 'N' INNER JOIN
                      parent_role_instances pri WITH (NOLOCK) ON pri.parent_role_instance_id = pc.party_role_id AND prn.party_b_role_id = pri.parent_role_instance_id AND 
                      is_set_up_cmpltd_ind = 'N' LEFT OUTER JOIN
                      party_contract pca WITH (NOLOCK) ON pca.party_role_id = prn.party_a_role_id AND pca.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcma WITH (NOLOCK) ON pcma.contract_id = pca.contract_id AND pcma.is_deleted_ind = 'N' AND 
                      pcma.is_set_up_cmpltd_ind = 'N' LEFT OUTER JOIN
                      party_contract pcb WITH (NOLOCK) ON pcb.party_role_id = pri.role_instance_id AND pcb.is_deleted_ind = 'N' LEFT OUTER JOIN
                      party_contract_manu pcmb WITH (NOLOCK) ON pcmb.contract_id = pcb.contract_id AND pcmb.is_deleted_ind = 'N' AND pcmb.is_set_up_cmpltd_ind = 'N'
WHERE     prn.inheritable_ind = 'Y' AND prn.is_deleted_ind = 'N';


-- dbo.Message_Logger source

create VIEW [dbo].[Message_Logger] AS 
SELECT tbm.trnsmt_msg_id, tm.party_id as partyid,tm.contract_cd,tm.selling_cd,tbm.system_nm,
replace(convert(varchar(12),tbm.request_date,106),' ','/') as request_date,convert(varchar(10),tbm.request_time, 108)as request_time,
tbm.lst_updt_userid as lst_updt_userid_clt,ats.trnsmt_status_nm,tbm.trnsmt_id,
 ats.trnsmt_status_nm   as trnsmt_status_id,tbm.response_bos_msg as response_bos_msg FROM transmittal_bos_msg tbm 
INNER JOIN transmittal_msg tm ON tm.trnsmt_msg_id = tbm.trnsmt_msg_id 
INNER JOIN adm_transmittal_status ats ON tbm.trnsmt_status_id = ats.trnsmt_status_id 
WHERE tbm.trnsmt_status_id<>6 and tbm.is_deleted_ind='N';


