-- dbo.PARTYCONTACTINFO source

CREATE VIEW [PARTYCONTACTINFO]
AS
SELECT DISTINCT 
                      dbo.party_addr.addr_line1, dbo.party_addr.addr_line2, dbo.party_addr.addr_line3, dbo.party_addr.city, dbo.party_addr.postal_cd, 
                      dbo.party_addr.no_of_years, dbo.adm_country.country_cd, dbo.adm_country.country_nm, dbo.adm_state.state_cd, dbo.adm_state.state_nm, 
                      dbo.adm_addr_type.addr_typ_nm, dbo.party_phn.country_cd AS Expr1, dbo.party_phn.area_cd, dbo.party_phn.phn_num, dbo.party_phn.extn_num, 
                      dbo.adm_phn_type.phn_typ_nm, dbo.party_internet.party_email, dbo.party_internet.party_internet_url, dbo.adm_internet_type.internet_typ_cd, 
                      dbo.adm_internet_type.internet_typ_nm, dbo.party.party_id
FROM         dbo.party INNER JOIN
                      dbo.party_addr ON dbo.party.party_id = dbo.party_addr.party_id LEFT OUTER JOIN
                      dbo.adm_country ON dbo.party_addr.country_id = dbo.adm_country.country_id LEFT OUTER JOIN
                      dbo.adm_state ON dbo.adm_country.country_id = dbo.adm_state.country_id LEFT OUTER JOIN
                      dbo.adm_addr_type ON dbo.party_addr.addr_typ_id = dbo.adm_addr_type.addr_typ_id LEFT OUTER JOIN
                      dbo.party_phn ON dbo.party.party_id = dbo.party_phn.party_id AND dbo.party_addr.party_addr_id = dbo.party_phn.party_addr_id LEFT OUTER JOIN
                      dbo.adm_phn_type ON dbo.party_phn.phn_typ_id = dbo.adm_phn_type.phn_typ_id LEFT OUTER JOIN
                      dbo.party_internet ON dbo.party.party_id = dbo.party_internet.party_id LEFT OUTER JOIN
                      dbo.adm_internet_type ON dbo.party_internet.internet_typ_id = dbo.adm_internet_type.internet_typ_id;


-- dbo.Question_v source

CREATE VIEW [Question_v]
AS
