FROM           screen_field_t;


-- dbo.Region_General source

CREATE VIEW [Region_General] AS

select   
b.party_id as partyid,
b.contract_id as contractid,
c.contract_cd as selling_cd,
e.party_role_nm   as Party_role,
   (select channel from channel_view x where x.channel_id=b.channel_id)channel_name,
       f.contract_status_nm as Code_Status,
         -- (select reason_nm from adm_reason x where x.reason_id=b.status_change_reason_id) Status_Change_Reason,
		    (select reason_nm from adm_Reason,adm_reason_typ_mapping
			where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
			and adm_reason_typ_mapping.reason_typ_map_id=b.status_change_reason_id ) Status_Change_Reason,
                  
            c.contract_start_dtm as Contract_Effective_Date_rg,
            c.contract_end_dtm      as Contract_Termination_Date_rg,
            --(select reason_nm from adm_reason x where x.reason_id=b.termination_reason_id) Termination_Reason,
			(select reason_nm from adm_Reason,adm_reason_typ_mapping
			where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
			and adm_reason_typ_mapping.reason_typ_map_id=b.termination_reason_id ) Termination_Reason,
            b.region_cd as RegionCode,
   (case when (b.code_set_up_ind='R' or b.code_set_up_ind='I') then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'') from party_contract_manu x with (NOLOCK) inner join party y with (NOLOCK) on x.party_id=y.party_id where x.region_cd=b.region_cd and x.code_set_up_ind='R') else null end)Region,
        
              b.ident     as Ident,
            g.contract_type_cd      as Contract_type_nm,
            g.contract_type_nm      as Contract_type_cd 
                     
from party_role_instance a with (NOLOCK) 
inner join party_contract_manu            b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N' and b.is_set_up_cmpltd_ind='N' 
inner join party_contract                 c with (NOLOCK) on b.contract_id=c.contract_id and a.role_instance_id=c.party_role_id and c.is_deleted_ind='N'
left outer join adm_party_role       e on a.party_role_id=e.party_role_id and e.is_deleted_ind='N'
left outer join adm_contract_status  f on c.contract_status_id=f.contract_status_id and f.is_deleted_ind='N'
left outer join adm_contract_type    g on c.contract_type_id=g.contract_type_id and g.is_deleted_ind='N'
where b.code_set_up_ind in ('R') and a.is_deleted_ind='N';


-- dbo.Roles source

CREATE VIEW [Roles] as
select  
a.party_id as partyid,
b.party_role_nm,
c.role_status_cd as status,
a.start_dtm as start_date,
a.end_dtm   as End_date
--convert(char(2),a.start_dtm,101)+'/'+substring(convert(char(6),a.start_dtm,113),4,3)+'/'+substring(convert(char(10),a.start_dtm,101),7,4)as start_date,
---convert(char(2),a.end_dtm,101)+'/'+substring(convert(char(6),a.end_dtm,113),4,3)+'/'+substring(convert(char(10),a.end_dtm,101),7,4)as End_date
from party_role a with (NOLOCK) 
LEFT OUTER JOIN adm_party_role        b on a.party_role_id=b.party_role_id and b.is_deleted_ind='N'
LEFT OUTER JOIN adm_party_role_status c on a.role_status_id=c.role_status_id  and c.is_deleted_ind='N'
where a.is_deleted_ind='N';


