-- dbo.adhoc_Recognition_v source

CREATE VIEW [adhoc_Recognition_v] as
select 
b.party_id           as partyid,
c.recgn_prg_typ_nm   as type,
d.recgn_level_nm     as Level,
b.recgn_start_dtm    as RecgStartdate,
b.recgn_end_dtm      as RecgEnddate
from  party_recgn b with (NOLOCK) 
left  outer join   adm_recgn_prg_type  c  on b.recgn_prg_typ_id=c.recgn_prg_typ_id and c.is_deleted_ind='N'
left  outer join   adm_recgn_level     d on  d.recgn_level_id=b.recgn_level_id and d.is_deleted_ind='N'
where b.is_deleted_ind='N';


-- dbo.adhoc_address_v source

CREATE VIEW [adhoc_address_v] as
select 
a.party_id     as Partyid, 
(c.addr_typ_nm +' '+ b.addr_id )as Address,
d.country_nm   as Country_desc,
b.postal_cd     as PostalCode,
b.addr_line3    as AdditionalMailingInfo,
b.addr_line1    as AddressLine1,
b.addr_line2    as AddressLone2,
e.state_nm      as StateName,
b.other_state   as OtherState,
b.city          as City,
case when b.bad_addr_ind='N' then 'No' else 'Yes'end 'BadAddressIndicator', 
case when b.addr_lock_ind='N' then 'No' else 'Yes'end 'addr_lock_ind',
case when b.over_ride_ind='N' then 'No' else 'Yes'end 'over_ride_ind'
from party a with (NOLOCK)
inner join      party_addr     b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N'
left outer join adm_addr_type  c on b.addr_typ_id=c.addr_typ_id and c.is_deleted_ind='N'
left outer join adm_country    d on d.country_id=b.country_id and d.is_deleted_ind='N'
left outer join adm_state      e on e.state_id=b.state_id and e.is_deleted_ind='N'
where  a.is_deleted_ind='N';


-- dbo.adhoc_branch_flag_v source

CREATE VIEW [adhoc_branch_flag_v] AS   
SELECT   DISTINCT
PCM.party_id as partyid,   
pcm.contract_id as contractid,   
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' when (legacy_code = Null or legacy_code ='') then 'false' else   
legacy_code end  from contract_legacy_code x where x.contract_id=pcm.contract_id and x.attribute_id=100004),'false'))Active_On_Extract,  
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' when (legacy_code = Null or   
legacy_code ='') then 'false' else legacy_code end from contract_legacy_code x where x.contract_id=pcm.contract_id and x.attribute_id=100006),'false'))Exclude_From_Extract,  
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N'then 'No' when (legacy_code = Null or legacy_code ='') then 'No' else legacy_code end from contract_legacy_code x where x.contract_id=pcm.contract_id and x.attribute_id=100019
),'No')) Group_Business_Allowed   
FROM party_contract_manu PCM with (NOLOCK)   
left outer join contract_legacy_code on contract_legacy_code.contract_id=PCM.contract_id   
left outer join adm_attribute on adm_attribute.attribute_id=contract_legacy_code.attribute_id and   
attribute_nm in ('Active On Extract','Exclude From Extract','Group Business Allowed')  
WHERE PCM.is_deleted_ind='N' and PCM.code_set_up_ind='B' and PCM.is_set_up_cmpltd_ind='N';


-- dbo.adhoc_bus_card_rule source

------------------------------------

CREATE VIEW adhoc_bus_card_rule AS
SELECT party_id as partyid,contract_code as selling_cd,contract_id as contractid,
(select addr_level_code from adm_level_channel_name 
where a.channel_id=channel_id and a.address_level_id=level_id and is_deleted_ind='N')'address_level_desc',
ISNULL((select addr_level_code from adm_level_channel_name 
where a.channel_id=channel_id and a.phone_level_id=level_id and is_deleted_ind='N'),'None')'phone_level_desc',
ISNULL((select addr_level_code from adm_level_channel_name 
where a.channel_id=channel_id and a.fax_level_id=level_id and is_deleted_ind='N'),'None') 'fax_level_desc',
ISNULL((select addr_level_code from adm_level_channel_name 
where a.channel_id=channel_id and a.email_level_id=level_id and is_deleted_ind='N'),'None') 'email_level_desc',
(select addr_level_code from adm_level_channel_name 
where a.channel_id=channel_id and a.name_level_id=level_id and is_deleted_ind='N') 'name_level_desc',
case when secondary_name_ind='Y' then 'Yes' else 'No' end 'secondary_name_ind',
case when distributor_nm_ind='Y' then 'Yes' else 'No' end 'distributor_nm_ind'
from bus_card_rule_level_contract_view a;


-- dbo.adhoc_bus_card_rule_info_v source

----------------------------------------------------------

CREATE VIEW adhoc_bus_card_rule_info_v as
select c.party_id as partyid,a.contract_id as contractid,c.contract_code,
b.address_level_id bus_card_level,c.level_id contract_level,
--- Added to get mailing_address info begin.
		--(select top 1 addr_line3 from party_role_addr x with (NOLOCK) inner join party_addr y with (NOLOCK)  on x.party_addr_id=y.party_addr_id where x.party_role_id=a.party_role_id and y.addr_id not like 'HM%'and x.is_deleted_ind='N')mailing_address,
(case when b.secondary_name_ind='Y' then (select top 1 addr_line3 from party_role_addr x 
with (NOLOCK) inner join party_addr y with (NOLOCK)  on x.party_addr_id=y.party_addr_id 
where x.party_role_id=a.party_role_id and y.addr_id not like 'HM%'and x.is_deleted_ind='N') 
else null end)mailing_address,
--- Added to get mailing_address info end.
--- Added to get distributor name ind info begin.
(case when b.distributor_nm_ind='Y' then (select top 1 COALESCE(first_nm,'')+' '+COALESCE(last_nm,'')
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party with (NOLOCK) on pcm.party_id=party.party_id and party.is_deleted_ind='N'
																	WHERE x.CONTRACT_ID=a.contract_id) 
else null end)distributor_name,
--- Added to get distributor name ind info end.

					(case when b.address_level_id=c.level_id then (select top 1 address from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id)
						  --when (select count(*) from party_contract_manu x where x.contract_id=a.parent_contract_id and x.level_id=b.address_level_id)>0 and  b.address_level_id < c.level_id  then (select address from bus_address_v x where x.contract_id=a.parent_contract_id)
						  when b.address_level_id > c.level_id  then (select top 1 address from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)
						---added channel level address begin
						  when b.address_level_id=100002 then
									(select top 1 (ltrim(rtrim(coalesce(addr_line1,'')))+
								ltrim(rtrim(coalesce(isnull(addr_line2,''),'')))+','+ltrim(rtrim(coalesce(city,'')))+','+ltrim(rtrim(coalesce(country_nm,'')))+','+ltrim(rtrim(coalesce(isnull(state_nm,other_state),'')))+','+ltrim(rtrim(coalesce(postal_cd,''))))  AS address
								from party_addr a with (NOLOCK)
								left outer join adm_country b on a.country_id=b.country_id 
								left outer join adm_state ast on a.state_id=ast.state_id
								inner join adm_channel y on y.stage_channel_id =c.channel_id
								WHERE ((channel='DC' and a.addr_typ_id in (100004)) or 
									   (channel<>'DC' and a.addr_typ_id in (100001,100003)))
								and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)
							---added channel level address end
						  else (select top 1 address from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth
                          )) end)address,
					(case when b.phone_level_id=c.level_id then (select top 1 phn_num+((case when extn_num='' then ('') else (isnull('('+extn_num+')','')) end))
																	from party_contract x with (NOLOCK)
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100001,100002,100005)
																	and x.CONTRACT_ID=a.contract_id)
						 when b.phone_level_id > c.level_id  then (select top 1 phn_num+((case when extn_num='' then ('') else (isnull('('+extn_num+')','')) end))
																	from party_contract x with (NOLOCK)
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100001,100002,100005)
																	and x.CONTRACT_ID=a.contract_id)
						      
                          ---added channel level phone begin
                           when b.phone_level_id = 100002  then (select  top 1 bb.phn_num+((case when extn_num='' then ('') else (isnull('('+extn_num+')','')) end)) from party_phn bb with (NOLOCK)
                                              inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                              where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
                                              and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
                                              and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
                          ---added channel level phone end
                                   
                                   else (select top 1 phn_num+((case when extn_num='' then ('') else (isnull('('+extn_num+')','')) end))
																	from party_contract x with (NOLOCK)
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100001,100002,100005)
																	and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
                                                                    )) end)phone,
					(case when b.fax_level_id=c.level_id then (select top 1 phn_num
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100003,100004)
																	and x.CONTRACT_ID=a.contract_id)
						 when b.fax_level_id > c.level_id  then (select top 1 phn_num
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100003,100004)
																	and x.CONTRACT_ID=a.contract_id)
						 
                          ---added channel level fax begin
                           when b.fax_level_id = 100002  then (select  top 1 bb.phn_num from party_phn bb with (NOLOCK) 
                                             inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                             where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
                                              and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
                                              and bb.phn_typ_id in (100003,100004) order by bb.phn_typ_id)
                          ---added channel level fax end

                                       else (select top 1 phn_num
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='N'
																	inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
																	WHERE c.phn_typ_id in (100003,100004)
																	and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.fax_level_id--order by level_depth
                                                                    )) end)fax,
				   (case when b.email_level_id=c.level_id then (select top 1 party_email
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
																	inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
																	WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
																	and x.CONTRACT_ID=a.contract_id)
						 when b.email_level_id > c.level_id  then (select top 1  party_email
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
																	inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
																	inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
																	WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
																	and x.CONTRACT_ID=a.contract_id)
						
                          ---added channel level email begin
                           when b.email_level_id = 100002  then (select  top 1 cc.party_email from party_internet cc with (NOLOCK) 
                                             inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                             where cc.party_id=c.channel_id and cc.is_deleted_ind='N' and  cc.internet_cd not like 'OTH%' 
                                             and ((channel='DC' and cc.internet_typ_id in (100001)) or (channel<>'DC' and cc.internet_typ_id in (100002)))
                                             order by cc.internet_typ_id)
                          ---added channel level email end
     
                                       else (select  top 1 party_email
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party_role_internet bi with (NOLOCK) on x.party_role_id=bi.party_role_id and bi.is_deleted_ind='N'
																	inner join party_internet c with (NOLOCK) on bi.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
																	inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
																	WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
																	and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.email_level_id--order by level_depth
                                                                    )) end)email,
                            
                               --- Added to get Name Level info begin.
                               (case when b.name_level_id=c.level_id then (select top 1 COALESCE(first_nm,'')+' '+COALESCE(last_nm,'')
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party with (NOLOCK) on pcm.party_id=party.party_id and party.is_deleted_ind='N'
																	WHERE x.CONTRACT_ID=a.contract_id)
						 when b.name_level_id > c.level_id  then (select top 1  COALESCE(first_nm,'')+' '+COALESCE(last_nm,'')
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party with (NOLOCK) on pcm.party_id=party.party_id and party.is_deleted_ind='N'
																	WHERE x.CONTRACT_ID=a.contract_id)
						
                          ---added channel level name info begin
                           when b.name_level_id = 100002  then (select  top 1 COALESCE(first_nm,'')+' '+COALESCE(last_nm,'') from party cc with (NOLOCK) 
                                             inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                             where cc.party_id=c.channel_id and cc.is_deleted_ind='N')
                          ---added channel level name info end
     
                                       else (select  top 1 COALESCE(first_nm,'')+' '+COALESCE(last_nm,'')
																	from party_contract x with (NOLOCK) 
																	inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
																	inner join party with (NOLOCK) on pcm.party_id=party.party_id and party.is_deleted_ind='N'
																	WHERE x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.name_level_id--order by level_depth
                                                                    )) end)name_info  
                               --- Added to get Name Level info end.     
from party_contract a with (NOLOCK) 
inner join party_contract_manu c with (NOLOCK) on a.contract_id=c.contract_id and c.is_deleted_ind='N' and c.is_set_up_cmpltd_ind='N'
inner join card_level_contract_view b on a.contract_id=b.contract_id
where a.is_deleted_ind='N';


-- dbo.adhoc_cac_channel_v source

/****** Object:  View [adhoc_cac_channel_v]    Script Date: 03/21/2009 22:15:12 ******/

CREATE VIEW [adhoc_cac_channel_v] AS
select 
a.party_id                  as partyid,
c.country_nm                as Country,
b.postal_cd                 as PostalCode,
b.additional_mailing_info   as AdditionalMailingInfo,
b.addr_line1                as AddressLine1,
b.addr_line2                as AddressLine2,
case when d.state_nm is null then b.other_state else d.state_nm end as State,
b.city                      as City,
e.phn_typ_nm                as Telephone,
b.phn_num                   as Number,
b.extn_num                  as Extension,
b.country_cd                as CountryCode,
b.party_email               as EmailAddress,
b.channel_id                as channel_id,
f.channel_desc  
from party a with (NOLOCK) 
inner join        party_channel_oper    b with (NOLOCK) on b.party_id=a.party_id and b.is_deleted_ind='N'
left outer join   adm_country           c on c.country_id=b.country_id  and c.is_deleted_ind='N'
left outer join   adm_state             d on d.state_id=b.state_id and d.is_deleted_ind='N'
left outer join   adm_phn_type          e on e.phn_typ_id=b.phn_typ_id and e.is_deleted_ind='N'
left outer join   channel_view          f on b.channel_id=f.channel_id
where b.channel_id =(select app_prop_value from adm_app_properties where app_prop_key='CAC_CHANNEL_ID')
 and a.is_deleted_ind='N';


-- dbo.adhoc_channel_def_card_rules_v source

---------------------------------------------

CREATE VIEW  adhoc_channel_def_card_rules_v AS
SELECT 

abcr.channel_id as partyid,
PTY.LAST_NM channelname,
a.addr_level_code address,
ISNULL(b.addr_level_code,'None') phone,
ISNULL(c.addr_level_code,'None') fax,
ISNULL(d.addr_level_code,'None') email,
e.addr_level_code distributor_name,
case when abcr.distributor_nm_ind='Y' then 'Yes' else 'No' end 'distributor_nm_ind',
case when abcr.secondary_name_ind='Y' then 'Yes' else 'No' end 'secondary_name_ind'


FROM adm_bus_card_rule abcr 

LEFT OUTER JOIN channel_view ON abcr.channel_id = channel_view.channel_id 
LEFT OUTER JOIN adm_level_channel_name a ON abcr.address_level_id = a.level_id and abcr.channel_id = a.channel_id 
LEFT OUTER JOIN adm_level_channel_name b ON abcr.phone_level_id = b.level_id and abcr.channel_id = b.channel_id 
LEFT OUTER JOIN adm_level_channel_name c ON abcr.fax_level_id = c.level_id and abcr.channel_id = c.channel_id 
LEFT OUTER JOIN adm_level_channel_name d ON abcr.email_level_id = d.level_id and abcr.channel_id = d.channel_id 
LEFT OUTER JOIN adm_level_channel_name e ON abcr.name_level_id = e.level_id and abcr.channel_id = e.channel_id
LEFT OUTER JOIN PARTY PTY with (NOLOCK) on abcr.channel_id=PTY.PARTY_ID 
where abcr.is_deleted_ind = 'N';


-- dbo.adhoc_channel_operations_v source

CREATE VIEW [adhoc_channel_operations_v] as
select 
a.party_id as partyid,
c.country_nm as Country,
b.postal_cd as PostalCode,
b.additional_mailing_info as AdditionalMailingInfo,
b.addr_line1 as AddressLine1,
b.addr_line2 as AddressLine2,
case when d.state_nm is null then b.other_state else d.state_nm end as State,
b.city as City,
e.phn_typ_nm as Telephone,
b.phn_num as Number,
b.extn_num as Extension,
b.country_cd as CountryCode,
b.party_email as EmailAddress
from party a with (NOLOCK) 
inner join party_channel_oper b with (NOLOCK) on b.party_id=a.party_id and b.is_deleted_ind='N'
left outer join adm_country c on c.country_id=b.country_id and c.is_deleted_ind='N'
left outer join adm_state d on d.state_id=b.state_id and d.is_deleted_ind='N'
left outer join adm_phn_type e on e.phn_typ_id=b.phn_typ_id and e.is_deleted_ind='N'
where a.is_deleted_ind='N';


-- dbo.adhoc_code_flag_v source

CREATE VIEW [adhoc_code_flag_v] AS    
SELECT  DISTINCT 
PCM.party_id  as partyid,
pcm.contract_id as contractid,    
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' 
when (legacy_code = Null or legacy_code='') then 'false' else    legacy_code end  from contract_legacy_code x with (NOLOCK) 
where x.contract_id=pcm.contract_id and x.attribute_id=100004 and x.is_deleted_ind ='N'),'false'))Active_On_Extract,    
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' when (legacy_code = Null or legacy_code='') 
then 'false' else    legacy_code end from contract_legacy_code x with (NOLOCK) 
where x.contract_id=pcm.contract_id and x.attribute_id=100005 and x.is_deleted_ind ='N'),'false'))CME_Participant,
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' 
when (legacy_code = Null or legacy_code='') then 'false' 
else  legacy_code end from contract_legacy_code x with (NOLOCK) 
where x.contract_id=pcm.contract_id and x.attribute_id=100006 and x.is_deleted_ind ='N'),'false'))Exclude_From_Extract,   
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' 
then 'No' when (legacy_code = Null or legacy_code='') then 'false' 
else    legacy_code end from contract_legacy_code x with (NOLOCK) where x.contract_id=pcm.contract_id 
and x.attribute_id=100007 and x.is_deleted_ind ='N'),'false')) Portfolio_Viewer,
(select isnull((select case when legacy_code='Y' then 'Yes' when legacy_code='N' then 'No' 
when (legacy_code = Null or legacy_code='') then 'false' else legacy_code end from contract_legacy_code x with (NOLOCK) 
where x.contract_id=pcm.contract_id and x.attribute_id=100023 and x.is_deleted_ind ='N'),'false')) pre_renewal_notice,
pcm.lst_updt_dtm as LastUpdateDateTime

FROM party_contract_manu PCM with (NOLOCK)    
left outer join contract_legacy_code on contract_legacy_code.contract_id=PCM.contract_id    
left outer join adm_attribute on adm_attribute.attribute_id=contract_legacy_code.attribute_id and    
attribute_nm in ('CME Participant', 'Active On Extract','Exclude From Extract','Portfolio Viewer','Pre-renewal Notice')   
WHERE PCM.is_deleted_ind='N' and PCM.code_set_up_ind='I' and PCM.is_set_up_cmpltd_ind='N';


-- dbo.adhoc_common_v source

CREATE VIEW[adhoc_common_v] as 
select 
party.party_id as partyid,
contract_id as contractid
from
party with (nolock)
left outer join party_contract_manu with (nolock) on party.party_id=party_contract_manu.party_id
where 
party.is_deleted_ind='N' and party_contract_manu.is_deleted_ind='N' and party_contract_manu.is_set_up_cmpltd_ind='N';


-- dbo.adhoc_communication_preferences_v source

CREATE VIEW [adhoc_communication_preferences_v] as  
select   
b.party_id as partyid,  
b.publish,  
c.pref_written_lang_nm as PreferredWritten,  
d.pref_spoken_lang_nm as PreferredSpoken,  
(case when written_ind=1 then f.lang_nm else null end) as OtherWritten,  
(case when spoken_ind=1 then f.lang_nm else null end) as OtherSpoken
from party_cmnctn_pref b with (NOLOCK)   
left outer join adm_pref_written_lang c on b.pref_written_lang_id=c.pref_written_lang_id AND c.is_deleted_ind='N'  
left outer join adm_pref_spoken_lang d on d.pref_spoken_lang_id=b.pref_spoken_lang_id AND d.is_deleted_ind='N'  
left outer join party_language e with (NOLOCK) on e.party_id=b.party_id AND e.is_deleted_ind='N'  
left outer join adm_lang f on e.lang_id=f.lang_id AND f.is_deleted_ind='N'  
where b.is_deleted_ind='N';


-- dbo.adhoc_contact_internet_v source

CREATE VIEW [adhoc_contact_internet_v] AS
select 
a.party_id as Partyid,
a.party_typ_id,       
pcm.contract_id as contractid, 
(e.internet_typ_nm +' '+ b.internet_cd)as EmailType,
(case when  pcm.code_set_up_ind='R' then cast(pcm.region_cd as varchar)
      when  pcm.code_set_up_ind='B' then cast(pcm.branch_cd as varchar) 
      else pc.contract_cd end) selling_cd ,
--b.internet_typ_id,
e.internet_typ_nm,
b.party_email,
case when b.lock_ind='Y' then 'Yes' else 'No' end 'lock_ind',
case when c.party_role_id is not null and pc.contract_id is not null then  'Yes' else 'No' end 'assigned'
from party a with (NOLOCK)
left outer join party_contract_manu pcm with (NOLOCK) on a.party_id=pcm.party_id and pcm.is_set_up_cmpltd_ind='N' and  pcm.is_deleted_ind='N'
left outer join party_contract pc with (NOLOCK) on pcm.contract_id=pc.contract_id and pc.is_deleted_ind='N'
left outer join party_role_instance pr with (NOLOCK) on pr.role_instance_id=pc.party_role_id and pr.is_deleted_ind='N'
left outer join party_role_internet c with (NOLOCK) on pc.party_role_id=c.party_role_id and c.is_deleted_ind='N'
left outer join party_internet b with (NOLOCK) on a.party_id=b.party_id and b.party_internet_id=c.party_internet_id  and b.is_deleted_ind='N'
left outer join adm_internet_type e on b.internet_typ_id=e.internet_typ_id  and e.is_deleted_ind='N'
where a.is_deleted_ind='N' and b.internet_typ_id is not null;


-- dbo.adhoc_contact_telephone_v source

CREATE VIEW [dbo].[adhoc_contact_telephone_v] AS
select 
a.party_id as Partyid,
a.party_typ_id,       
pcm.contract_id as contractid, 
(e.phn_loc_nm  +' '+b.phn_cd) as TelephoneLocation,
(case when  pcm.code_set_up_ind='R' then cast(pcm.region_cd as varchar)
      when  pcm.code_set_up_ind='B' then cast(pcm.branch_cd as varchar) 
      else pc.contract_cd end) selling_cd ,
--b.phn_typ_id,
--e.phn_loc_nm,
h.phn_typ_nm as phn_loc_nm,
b.phn_num,
b.extn_num,
b.country_cd,
case when b.lock_ind='Y' then 'Yes' else 'No' end 'lock_ind',
case when c.party_role_id is not null and pc.contract_id is not null then  'Yes' else 'No' end 'assigned'
from party a with (NOLOCK) 
left outer join party_contract_manu pcm with (NOLOCK) on a.party_id=pcm.party_id and pcm.is_set_up_cmpltd_ind='N' and  pcm.is_deleted_ind='N'
left outer join party_contract pc with (NOLOCK) on pcm.contract_id=pc.contract_id and pc.is_deleted_ind='N'
left outer join party_role_instance pr with (NOLOCK) on pr.role_instance_id=pc.party_role_id and pr.is_deleted_ind='N'
left outer join party_role_phn c with (NOLOCK) on  pc.party_role_id=c.party_role_id and c.is_deleted_ind='N'
left outer join party_phn b with (NOLOCK) on a.party_id=b.party_id  and b.party_phn_id=c.party_phn_id and b.is_deleted_ind='N'
left outer join adm_party_phn_location e on b.phn_loc_id=e.phn_loc_id and e.is_deleted_ind='N'
left outer join adm_phn_type h on h.phn_typ_id=b.phn_typ_id and h.is_deleted_ind='N'
where a.is_deleted_ind='N' and b.phn_typ_id is not null;


-- dbo.adhoc_contract_bank_v source

CREATE VIEW [adhoc_contract_bank_v] AS

SELECT distinct  
 PCM.party_id as partyid,  
 PC.contract_id as contractid,  
 AB.bank_nm,  
 PBI.transit_num,  
 PBI.name_on_account,  
 ABT.bank_acct_typ_nm,  
 PBI.account_num,  
 PBI.start_dtm,  
 PBI.end_dtm,  
 case when prb.party_role_id is not null and pc.contract_id is not null then 'Yes' else 'No' end 'assigned'  
  
FROM  
 PARTY_ROLE_BANK PRB with (NOLOCK)   
 INNER JOIN PARTY_CONTRACT PC with (NOLOCK) on PC.party_role_id=PRB.party_role_id and PC.is_deleted_ind='N'   
 INNER JOIN party_contract_manu PCM with (NOLOCK) ON PCM.contract_id=PC.contract_id and PCM.is_deleted_ind='N' AND PCM.is_set_up_cmpltd_ind='N'    
 LEFT OUTER JOIN party_bank_info PBI with (NOLOCK) ON PBI.party_id=PCM.party_id and 
 PBI.party_bank_id=PRB.party_bank_id and PBI.is_deleted_ind='N'   
 LEFT OUTER JOIN adm_bank AB ON PBI.bank_id=AB.bank_id and AB.is_deleted_ind='N'  
 LEFT OUTER JOIN adm_bank_acct_type ABT ON PBI.bank_acct_typ_id=ABT.bank_acct_typ_id and ABT.is_deleted_ind='N'   
 left outer join party_role_instance pr with (NOLOCK) on pr.role_instance_id=pc.party_role_id and pr.is_deleted_ind='N'   
 where PRB.is_deleted_ind='N';


-- dbo.adhoc_contract_history_v source

CREATE VIEW [adhoc_contract_history_v] AS
select 
p.party_id as partyid,
pm.contract_id as contractid,
ch.contract_code as Code,
ch.ident as Ident,
ch.contract_type_nm as Contract_Type,
cs.contract_status_nm as contract_status,
ch.contract_status_id,
pm.contract_code as reporting_Controller_code,
ch.rept_cntrl_contract_type_nm as reporting_controller_contract_type,
ch.rept_cntrl_nm as reporting_controller_name,
ch.branch_cd as branch_code,
ch.branch_contract_type_nm as branch_contract_type,
ch.branch_nm as branch_name,
ch.region_cd as region_code,
ch.region_contract_type_nm as region_contract_type,
ch.region_nm as region_name,
CAST(FLOOR(CAST(ch.start_dt AS float)) AS datetime) as ch_start_date,
CAST(FLOOR(CAST(ch.end_dt AS float)) AS datetime) as ch_end_date,
ch.branch_nm_clt as branch_name_clt,
ch.rept_cntrl_nm_clt as reporting_controller_name_clt,
ch.region_nm_clt as region_name_clt
from contract_history ch with (NOLOCK)
left outer join party_contract_manu pm with (NOLOCK) on ch.rept_cntrl_cd=pm.contract_id and pm.is_deleted_ind='N'
left outer join party p with (NOLOCK) on pm.party_id=p.party_id and p.is_deleted_ind='N' 
left outer join adm_contract_status cs on ch.contract_status_id=cs.contract_status_id and cs.is_deleted_ind='N' 
WHERE ch.is_deleted_ind='N';


-- dbo.adhoc_contract_lob_v source

CREATE VIEW [adhoc_contract_lob_v] as

select * from 
(SELECT PCM.party_id  as partyid,
	PC.contract_id as contractid,
	CBI.lst_updt_dtm as balance_upd_dtm ,
	CBI.current_bal,
	CBI.negotiated_debit_bal,
	CBI.rolled_debit_bal,
	(select max(CLDS.lst_updt_dtm) from contract_lob_dept_status CLDS where cbi.selling_cd=clds.selling_cd) 'LOB_Last_Updated',
	dept_nm,
	dept_ind,
	system_nm,
	system_ind,
	pc.contract_cd,
    CBI.is_deleted_ind as balanceflag,
	CLB.is_deleted_ind as deptflag
	
FROM
	party_contract_manu PCM  with (NOLOCK) 
	inner join party_contract PC with (NOLOCK) on PCM.contract_id=pc.contract_id AND PC.is_deleted_ind='N'
	left outer join contract_balance_income CBI with (NOLOCK) on CBI.SELLING_CD =PC.contract_cd  AND CBI.is_deleted_ind='N'	
	left outer join contract_lob_dept_status CLB with (NOLOCK) on pc.contract_cd=CLB.selling_cd and clb.is_deleted_ind='N'	
    WHERE PCM.is_deleted_ind='N' AND PCM.is_set_up_cmpltd_ind='N')a

where (balanceflag is not null or deptflag is not null);


-- dbo.adhoc_contract_report_control_v source

CREATE VIEW  [adhoc_contract_report_control_v] as

select 

acrc.report_channel_id as partyid,
contract_report_cntrl_id,
act.contract_type_cd as contractType,
al.level_desc as level,
arct.contract_type_cd as reportContractType,
arl.level_desc as reportLevel,
cv.channel_desc 

from adm_contract_report_cntrl acrc 
left join adm_contract_type act on act.contract_type_id=acrc.contract_type_id AND act.is_deleted_ind='N' 
left join adm_levels al on al.level_id=acrc.level_id AND al.is_deleted_ind='N' 
left join adm_contract_type arct on arct.contract_type_id=acrc.report_contract_type_id AND arct.is_deleted_ind='N' 
left join adm_levels arl on arl.level_id=acrc.report_level_id AND arl.is_deleted_ind='N' 
left join channel_view cv on cv.channel_id=acrc.report_channel_id
where acrc.is_deleted_ind='N';


-- dbo.adhoc_contract_requirement_v source

CREATE VIEW [adhoc_contract_requirement_v] AS
select 

a.party_id as partyid, 
a.contract_id as contractid ,
c.requirement_typ_nm,
d.requirement_status_nm,
a.contract_code

from party_contract_manu a with (NOLOCK)
inner join party_contract_requirement b with (NOLOCK) on a.contract_id=b.contract_id and b.is_deleted_ind='N'
inner JOIN adm_requirement_type c ON b.requirement_typ_id=c.requirement_typ_id and c.is_deleted_ind='N'
inner JOIN adm_requirement_status d ON b.requirement_status_id=d.requirement_status_id and d.is_deleted_ind='N'
where a.is_deleted_ind='N' AND a.is_set_up_cmpltd_ind='N' 

union

select
a.party_id as partyid, 
a.contract_id as contractid ,
e.requirement_nm as requirement_typ_nm,
d.requirement_status_nm,
a.contract_code

from party_contract_manu a with (NOLOCK)
inner JOIN contract_custom_requirement e with (NOLOCK) on a.contract_id=e.contract_id and e.is_deleted_ind='N'
inner JOIN adm_requirement_status d ON e.requirement_status_id=d.requirement_status_id and d.is_deleted_ind='N'
where a.is_deleted_ind='N' AND a.is_set_up_cmpltd_ind='N';


