-- dbo.adhoc_contracts_v source

CREATE VIEW [adhoc_contracts_v] AS
 
select  

pcm.party_id as partyid,
pcm.contract_id as contractid,
case when pcm.code_set_up_ind='R' then  CAST(pcm.region_cd AS varchar) 
     when pcm.code_set_up_ind='B' then CAST(pcm.branch_cd AS varchar) 
     when pcm.code_set_up_ind='I' then CAST(isnull(pc.contract_cd, '')as varchar) end 'contracts_contract_code' ,
pcm.ident as Contracts_Ident,
(case when pcm.code_set_up_ind='I' then pcm.branch_cd when pcm.code_set_up_ind='B' then (select xp.branch_cd from party_contract_manu xp with (NOLOCK) where xp.contract_id=pcm.reporting_cont_cd  ) else null end) contracts_branch_code ,
(case when pcm.code_set_up_ind='I' then 
			(select top 1 last_nm from party_contract_manu x with (NOLOCK) inner join party b with (NOLOCK) on x.party_id=b.party_id where x.contract_id=pc.parent_contract_id) 
      when (select xp.code_set_up_ind from party_contract_manu xp with (NOLOCK) where xp.contract_id=pcm.reporting_cont_cd )='B' then 
			(select top 1 last_nm from party_contract_manu x with (NOLOCK) inner join party b with (NOLOCK) on x.party_id=b.party_id where x.contract_id=pcm.reporting_cont_cd and x.is_deleted_ind='N') else null end) contracts_branch_name, 
act.contract_type_nm as Contracts_Contract_Type,
acs.contract_status_nm as Contracts_Contract_Status

from party_contract_manu pcm with (NOLOCK) 
inner join party_contract pc with (NOLOCK) on pc.contract_id=pcm.contract_id AND pc.is_deleted_ind='N' 
left outer join adm_contract_type act on act.contract_type_id=pc.contract_type_id  AND act.is_deleted_ind='N'
left outer join adm_contract_status acs on acs.contract_status_id=pc.contract_status_id and acs.is_deleted_ind='N'

where pcm.is_deleted_ind='N' and pcm.is_set_up_cmpltd_ind='N';


-- dbo.adhoc_dc_channel_v source

CREATE VIEW [adhoc_dc_channel_v] AS
select 
a.party_id                  as partyid,
c.country_nm                as Country,
b.postal_cd                 as PostalCode,
b.additional_mailing_info   as AdditionalMailingInfo,
b.addr_line1                as AddressLine1,
b.addr_line2                as AddressLine2,
case when d.state_nm is null then b.other_state else d.state_nm end as State,
b.city                      as City,
e.phn_typ_nm                as Telephone,
b.phn_num                   as Number,
b.extn_num                  as Extension,
b.country_cd                as CountryCode,
b.party_email               as EmailAddress,
b.channel_id                as channel_id,
f.channel_desc  
from party a with (NOLOCK) 
inner join        party_channel_oper    b with (NOLOCK) on b.party_id=a.party_id AND b.is_deleted_ind='N'
left outer join   adm_country           c on c.country_id=b.country_id AND c.is_deleted_ind='N' 
left outer join   adm_state             d on d.state_id=b.state_id AND d.is_deleted_ind='N'
left outer join   adm_phn_type          e on e.phn_typ_id=b.phn_typ_id AND e.is_deleted_ind='N'
left outer join   channel_view           f on b.channel_id=f.channel_id
where b.channel_id =(select app_prop_value from adm_app_properties where app_prop_key='DC_CHANNEL_ID')
and  a.is_deleted_ind='N';


