-- dbo.adhoc_notes_v source

CREATE VIEW [adhoc_notes_v]  AS
select --distinct 
pcm.party_id 'partyid',
pcm.contract_id as contractid,
(Case when pcm.code_set_up_ind='R' then CAST(pcm.region_cd AS varchar)
when pcm.code_set_up_ind='B' then CAST(pcm.branch_cd AS varchar)
when pcm.code_set_up_ind='I' then CAST(isnull(pc.contract_cd, '') as varchar)end)  'selling_cd',
convert(varchar,note_cr_dtm,101)note_cr_dtm,
user_nm,
subject,
--(case when LEN( CONVERT(VARCHAR,notes ))>25 then LEFT(CONVERT(VARCHAR,notes ), 25)+'....' else CONVERT(VARCHAR,notes ) end) as notes
 notes 
from  party_contract_manu pcm with (NOLOCK) 
inner JOIN notes with (NOLOCK) ON pcm.contract_id=notes.contract_id AND notes.is_deleted_ind='N' 
inner JOIN party_contract pc with (NOLOCK) ON pcm.contract_id=pc.contract_id AND pc.is_deleted_ind='N' 
where pcm.is_deleted_ind='N' AND PCM.is_set_up_cmpltd_ind='N';


-- dbo.adhoc_partyinternet_v source

CREATE VIEW [adhoc_partyinternet_v] as
select 
a.party_id as partyid,
(b.internet_typ_nm +' '+ a.internet_cd)as EmailType,
a.party_email as EmailAddress,
case when a.lock_ind='N' then 'No' else 'Yes'end 'Donotchange',
c.identifier_value
from party_internet a with (NOLOCK) 
left outer join adm_internet_type b on b.internet_typ_id=a.internet_typ_id 
and b.is_deleted_ind='N'
left outer join party_identifier c with (NOLOCK) on a.party_id=c.party_id 
and c.identifier_typ_id=100004 and c.is_deleted_ind='N'
where a.is_deleted_ind='N';


-- dbo.adhoc_publications_v source

CREATE VIEW [dbo].[adhoc_publications_v]  AS  
select   
p.party_id as partyid,  
n.publctns_nm_desc as PublicationName,  
f.publctns_frmt_desc as Format,  
l.pref_written_lang_nm as Language,  
p.no_of_copies as NumberOfCopies,  
case when p.unsubscrb_ind='Y' then 'Yes' when p.unsubscrb_ind='N' then 'No' end 'Unsubscribe'   
   
from  party_publications p  
  
INNER JOIN party b  ON p.party_id=b.party_id AND p.is_deleted_ind='N'   
  
INNER JOIN adm_publctns_name n  ON p.publctns_nm_id=n.publctns_nm_id AND p.is_deleted_ind='N'   
  
INNER JOIN adm_publctns_frmt f  ON p.publctns_frmt_id=f.publctns_frmt_id AND p.is_deleted_ind='N'   
  
INNER JOIN adm_pref_written_lang l  ON p.lang_id=l.pref_written_lang_id AND p.is_deleted_ind='N';


-- dbo.adhoc_relationship_new_v source

CREATE VIEW [adhoc_relationship_new_v] as
select pri.party_id as partyid, 
--cast(prn.from_party_id as varchar) as frompartyname, 
(select adm_party_role.party_role_nm from party_role_instance with (nolock) 
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
where party_role_instance.role_instance_id = prn.party_a_role_id and party_role_instance.party_id=pri.party_id) as frmpartyrole, 
prn.party_lvl_from_ind as frm_lvl_ind,
(case when pcma.code_set_up_ind ='I' then pca.contract_cd 
when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar) 
when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end) 
AS FRM_CODE,(case when pcmb.code_set_up_ind ='I' then pcb.contract_cd 
when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar) 
when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE, 
cast(prn.to_party_id as varchar) as topartyid, 
--cast(prn.to_party_id as varchar) as topartyname, 
(select  adm_party_role.party_role_nm from party_role_instance with (nolock)
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
where party_role_instance.role_instance_id = prn.party_b_role_id and prn.to_party_id=party_role_instance.party_id) 
as topartyrole, prn.party_lvl_to_ind as to_lvl_ind, prn.relationship_status, null as inhrdfrmpartyid, 
prn.relationship_start_dt effectiveDate,prn.relationship_end_dt terminationDate,prn.inheritable_ind isinteritable,
(select title from party p where p.party_id=prn.to_party_id and is_deleted_ind='N') as title
from party_relationship_ncr prn with (NOLOCK) 
inner join party_role_instance pri with (NOLOCK) on prn.party_a_role_id = pri.role_instance_id and pri.is_deleted_ind='N'  
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=prn.party_a_role_id and pca.is_deleted_ind='N' 
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N' 
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=prn.party_b_role_id and pcb.is_deleted_ind='N' 
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N' 
where  prn.is_deleted_ind='N'
union 
select	pcm.party_id, 
		--cast(pcm.party_id as varchar) as frompartynm,
		(select adm_party_role.party_role_nm from party_role_instance with (nolock)
		 inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
		where party_role_instance.role_instance_id = pri.role_instance_id and party_role_instance.party_id=pcm.party_id) as frompartyrole,
	    null as from_lvl_ind,
		(case when pcma.code_set_up_ind ='I' then pca.contract_cd 
			  when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar) 
			  when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end) AS FROM_CODE,
		(case when pcmb.code_set_up_ind ='I' then pcb.contract_cd 
			  when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar) 
			  when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE,
		prn.to_party_id as topartyid,
		--cast(prn.to_party_id as varchar) as topartyname,
		(select adm_party_role.party_role_nm from party_role_instance with (nolock)
			inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
			where party_role_instance.role_instance_id = prn.party_b_role_id and prn.to_party_id=party_role_instance.party_id) as topartyrole,
			null as to_lvl_ind,
		prn.relationship_status,
		prn.from_party_id as inhrdfrompartyid,
		prn.relationship_start_dt effectiveDate,prn.relationship_end_dt terminationDate,prn.inheritable_ind isinteritable,
		(select title from party p where p.party_id=prn.to_party_id and is_deleted_ind='N') as title

from party_contract_manu pcm with (NOLOCK) 
inner join party_contract pc with (NOLOCK) on pc.contract_id=pcm.contract_id and  pc.is_deleted_ind='N' 
inner join parent_role_instances pri with (NOLOCK) on pri.role_instance_id = pc.party_role_id 
inner join party_relationship_ncr prn with (NOLOCK) on prn.party_a_role_id = pri.parent_role_instance_id and prn.inheritable_ind = 'Y' and prn.is_deleted_ind='N' 
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=pri.role_instance_id and pca.is_deleted_ind='N' 
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N' 
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=prn.party_b_role_id and pcb.is_deleted_ind='N' 
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N' 
where  pcm.is_deleted_ind='N' and pcm.is_set_up_cmpltd_ind='N'
union 
select prn.from_party_id party_id,
--cast(prn.from_party_id as varchar) as frompartynm,
(select adm_party_role.party_role_nm from party_role_instance with (nolock)
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
where party_role_instance.role_instance_id = prn.party_a_role_id 
and party_role_instance.party_id=prn.from_party_id) as frompartyrole,
null as from_lvl_ind,
(case when pcma.code_set_up_ind ='I' then pca.contract_cd 
when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar) 
when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end) 
AS FROM_CODE,(case when pcmb.code_set_up_ind ='I' then pcb.contract_cd 
when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar) 
when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE,
(select party_id from party_role_instance pr with (nolock) where pr.role_instance_id=pri.role_instance_id) 
as topartyid,
--(select cast(party_role_instance.party_id as varchar) from party_role_instance where party_role_instance.role_instance_id=pri.role_instance_id 
--) as topartyname,
(select  top (1) adm_party_role.party_role_nm from party_role_instance with (nolock)
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id 
where (party_role_instance.role_instance_id = pri.role_instance_id)) 
as topartyrole,null as to_lvl_ind,prn.relationship_status,prn.to_party_id as inhrdfrompartyid,
		prn.relationship_start_dt effectiveDate,prn.relationship_end_dt terminationDate  ,prn.inheritable_ind isinteritable,
(select title from party p where p.party_id=(select party_id from party_role_instance pr where pr.role_instance_id=pri.role_instance_id and is_deleted_ind='N') and is_deleted_ind='N') as title
from party_relationship_ncr prn with (NOLOCK) 
inner join party_contract pc with (NOLOCK) on pc.party_role_id=prn.party_b_role_id and pc.is_deleted_ind='N' 
inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=pc.contract_id and pcm.is_deleted_ind='N' and is_set_up_cmpltd_ind='N' 
inner join parent_role_instances pri with (NOLOCK) on pri.parent_role_instance_id = pc.party_role_id and prn.party_b_role_id = pri.parent_role_instance_id  and is_set_up_cmpltd_ind='N' 
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=prn.party_a_role_id and pca.is_deleted_ind='N' 
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N' 
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=pri.role_instance_id and pcb.is_deleted_ind='N' 
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N' 
where prn.inheritable_ind = 'Y' and prn.is_deleted_ind='N';


-- dbo.adhoc_suitability_v source

CREATE VIEW [adhoc_suitability_v] as
select 
a.party_id             as partyid,
c.suitability_typ_nm   as Type,
b.start_dtm            as SuitabilityStartDate,
b.end_dtm              as SuitabilityEndDate,
b.notes                as Suitabilitynotes,
--d.reason_nm            as SuitabilityReason
(select reason_nm from adm_reason where reason_id=d.reason_id) SuitabilityReason
from party a with (NOLOCK) 
inner join         party_suitability_info b with (NOLOCK) on b.party_id=a.party_id and b.is_deleted_ind='N'
left outer join    adm_suitability_type   c on c.suitability_typ_id=b.suitability_typ_id and c.is_deleted_ind='N'
left outer join adm_reason_typ_mapping d on d.reason_typ_map_id=b.suitability_reason_id and d.is_deleted_ind='N'
--left outer join    adm_suitability_reason   d on d.suitability_reason_id=b.suitability_reason_id and d.is_deleted_ind='N'
where a.is_deleted_ind='N';


-- dbo.adhoc_telephone_v source

CREATE VIEW [adhoc_telephone_v]  as
select 
a.party_id         as partyid,
(c.phn_loc_nm  +' '+b.phn_cd) as TelephoneLocation,
d.phn_typ_nm       as TelephoneType,
b.phn_num          as Number,
b.extn_num         as Extension,
b.country_cd       as Countrycode,
case when b.lock_ind='N' then 'No' else 'Yes'end 'lock_ind'
from party a with (NOLOCK) 
inner join          party_phn              b with (NOLOCK) on a.party_id=b.party_id  and b.is_deleted_ind='N'
left outer join     adm_party_phn_location c on b.phn_loc_id=c.phn_loc_id and c.is_deleted_ind='N'
left outer join     adm_phn_type           d on d.phn_typ_id=b.phn_typ_id and d.is_deleted_ind='N'
left outer join     adm_country            e on b.country_cd=e.country_cd and d.is_deleted_ind='N'
where a.is_deleted_ind='N';


-- dbo.branch_general source

CREATE VIEW [branch_general] as
select b.party_id as partyid,
		b.contract_id as contractid,
		c.contract_cd as selling_cd,
		b.branch_cd as Manulife_branch_code, 
		e.party_role_nm	as Party_role,
		(select channel from channel_view x where x.channel_id=b.channel_id)channel_name,
		f.contract_status_nm as Code_Status,		
		(select reason_nm from adm_Reason,adm_reason_typ_mapping where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
				and adm_reason_typ_mapping.reason_typ_map_id=b.status_change_reason_id ) Status_Change_Reason,
		c.contract_start_dtm as Contract_Effective_Date_bg,
		c.contract_end_dtm as Contract_Termination_Date_bg,
		(select reason_nm from adm_Reason,adm_reason_typ_mapping where adm_Reason.reason_id=adm_reason_typ_mapping.reason_id
				and adm_reason_typ_mapping.reason_typ_map_id=b.termination_reason_id )  Termination_Reason,
       cast(b.region_cd as varchar) as RegionCode,
		(case when b.code_set_up_ind='B' then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'') from party_contract_manu x inner join party y on x.party_id=y.party_id where x.contract_id=c.parent_contract_id) else null end)Region_Desc,
		(case when b.code_set_up_ind='B' then (select contract_type_nm  from party_contract x inner join   adm_contract_type y on  x.contract_id=c.parent_contract_id where x.contract_type_id=y.contract_type_id ) else null end) 'Region_Contract_Type',
			
    	(case when b.code_set_up_ind='B' then (select contract_type_cd  from party_contract x inner join   adm_contract_type y on  x.contract_id=c.parent_contract_id where x.contract_type_id=y.contract_type_id ) else null end) 'Region_Contract_Cd',
	         
		b.ident	as Ident,
		g.contract_type_cd as Contract_type_desc,
        g.contract_type_nm as Contract_type,   
(select contract_type_nm from adm_contract_type x where x.contract_type_id=b.reporting_cont_contract_type_id)Reporting_Controller_Contract_Type,
		(select contract_type_cd from adm_contract_type x where x.contract_type_id=b.reporting_cont_contract_type_id)Reporting_Controller_Contract_Type_DESC,
		--b.reporting_cont_cd as Reporting_Controller_Code, 
		(case when (select code_set_up_ind from party_contract_manu x with (NOLOCK)  where x.contract_id=b.reporting_cont_cd)='R' 
				then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'')  from party_contract_manu x inner join party y on x.party_id=y.party_id where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='R' ) 
			  when (select code_set_up_ind from party_contract_manu x with (NOLOCK)  where x.contract_id=b.reporting_cont_cd)='B' 
				then (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'')  from party_contract_manu x inner join party y on x.party_id=y.party_id where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='B' ) 				
			  else (select top 1 coalesce(last_nm,'')+' '+coalesce(first_nm,'')+' '+coalesce(middle_nm,'')  from party_contract_manu x inner join party y on x.party_id=y.party_id where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='I' ) 
	          end)Reporting_Controller_NAME,
(case when (select code_set_up_ind from party_contract_manu x with (NOLOCK) where x.contract_id=b.reporting_cont_cd)='R' 
				then (select top 1 cast(x.region_cd as varchar)  from party_contract_manu x  where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='R' ) 
			  when (select code_set_up_ind from party_contract_manu x with (NOLOCK) where x.contract_id=b.reporting_cont_cd)='B' 
				then (select top 1 cast(x.region_cd as varchar)  from party_contract_manu x  with (NOLOCK) where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='B' ) 				
			  else (select top 1 cast(x.region_cd as varchar)  from party_contract_manu x with (NOLOCK) where x.contract_id=b.reporting_cont_cd and x.code_set_up_ind='I' ) 
	          end)Reporting_Controller_Code,
	

		--i.reporting_cntrl_reas as Reporting_Controller_Change_Reason,
		(select reason_nm from adm_reason where reason_id=i.reason_id) Reporting_Controller_Change_Reason,
		--(select contract_cd from party_contract with (NOLOCK) where contract_id= b.payment_cont_cd)as Payment_Controller_Code,				
		--h.pay_cntrl_reas  as Payment_Controller_Change_Reason,
		--(select reason_nm from adm_reason where reason_id=h.reason_id) Payment_Controller_Change_Reason,
		dc.legacy_code as DC_Dataphile_Branch_Code,
		mbc.legacy_code as Maritime_Branch_Code,
		mbsc.legacy_code as Maritime_Branch_Selling_Code,
		c.contract_cd Manulife_Selling_Code,
		(select tax_indicator from adm_tax_indicator x where x.tax_indicator_id=b.tax_ind_id)Tax_Indicator
from party_role_instance a with (NOLOCK) 
inner join party_contract_manu		 b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N' and b.is_set_up_cmpltd_ind='N'
inner join party_contract			 c with (NOLOCK) on b.contract_id=c.contract_id and a.role_instance_id=c.party_role_id and c.is_deleted_ind='N'
left outer join adm_party_role       e on a.party_role_id=e.party_role_id and e.is_deleted_ind='N'
left outer join adm_contract_status  f on c.contract_status_id=f.contract_status_id and f.is_deleted_ind='N'
left outer join adm_contract_type    g on c.contract_type_id=g.contract_type_id and g.is_deleted_ind='N'
--left outer join adm_pay_cntrl_reas   h on h.pay_cntrl_reas_id=b.payment_cont_change_reason_id
--left outer join adm_report_contrl_reas i on b.reporting_cont_change_reason_id=i.reporting_cntrl_reas_id
--left outer join adm_reason_typ_mapping   h on h.reason_typ_map_id=b.payment_cont_change_reason_id and h.is_deleted_ind='N'
left outer join adm_reason_typ_mapping i on b.reporting_cont_change_reason_id=i.reason_typ_map_id and i.is_deleted_ind='N'
--left outer join contract_legacy_code j with (NOLOCK) on b.contract_id=j.contract_id --and j.attribute_id in (100009,100017,100008) and j.is_deleted_ind='N'

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100009) dc on
dc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100017) mbc on
 mbc.contract_id=c.contract_id

left outer join (select legacy_code,contract_id from contract_legacy_code WITH(NOLOCK) where attribute_id=100008) mbsc on
mbsc.contract_id=c.contract_id

where b.code_set_up_ind='B' and a.is_deleted_ind='N';


-- dbo.bus_address_v source

CREATE VIEW [bus_address_v] as  
select   
 a.contract_id,  
 pcm.level_id,  
 c.party_addr_id,  
 c.addr_typ_id,c.addr_id,  
 (ltrim(rtrim(coalesce(addr_line1,'')))+ltrim(rtrim(coalesce(isnull(addr_line2,''),'')))+','+ltrim(rtrim(coalesce(city,'')))+','+ltrim(rtrim(coalesce(country_nm,'')))+','+ltrim(rtrim  
 (coalesce(isnull(state_nm,other_state),'')))+','+ltrim(rtrim(coalesce(postal_cd,''))))  AS address ,   
 addr_line1,  
 addr_line2,  
 city,  
 country_nm,  
 isnull(state_nm,other_state) state,  
 postal_cd,  
 bad_addr_ind,  
 c.country_id,  
 isnull(c.state_id,'') state_id  ,
 case when state_nm is null then other_state else '' end other_state
   
from party_contract a with (nolock)    
inner join party_contract_manu pcm with (nolock) on pcm.contract_id=a.contract_id    
inner join party_role_addr b with (nolock) on a.party_role_id=b.party_role_id and b.is_deleted_ind='N'    
inner join party_addr c with (nolock) on b.party_addr_id=c.party_addr_id and c.is_deleted_ind='N' and addr_id not like 'HM%'    
left outer join adm_country d on c.country_id=d.country_id    
left outer join adm_state e on c.state_id=e.state_id    
--added to get address based on channel - begin    
inner join adm_channel y on y.stage_channel_id =pcm.channel_id    
        WHERE ((channel='DC' and c.addr_typ_id in (100004)) or     
            (channel<>'DC' and c.addr_typ_id in (100001,100003)))    

--added to get address based on channel - End;


-- dbo.bus_card_rule_level_contract_view source

------------------------------

CREATE view bus_card_rule_level_contract_view as
select	AA.contract_id,contract_code,party_id,AA.channel_id,party_role_id,level_id,derived_contract_id,
		ISNULL(cbc.address_level_id,abc.address_level_id)address_level_id,
		(case when cbc.name_level_id is not null then cbc.phone_level_id else abc.phone_level_id end)phone_level_id,
		(case when cbc.name_level_id is not null then cbc.fax_level_id else abc.fax_level_id end)fax_level_id,
		(case when cbc.name_level_id is not null then cbc.email_level_id else abc.email_level_id end)email_level_id,
        ISNULL(cbc.name_level_id,abc.name_level_id)name_level_id,
        ISNULL(cbc.secondary_name_ind,abc.secondary_name_ind)secondary_name_ind,
        ISNULL(cbc.distributor_nm_ind,abc.distributor_nm_ind)distributor_nm_ind
 from 
(select pc.contract_id,pcm.contract_code,pcm.party_id,pcm.channel_id,pc.party_role_id,pcm.level_id,(case when (select count(1) from party_contract A with (nolock) inner JOIN contract_bus_card_rule B with (nolock) ON A.CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id) > 0
		    then (select a.CONTRACT_ID from party_contract A with (nolock) inner JOIN contract_bus_card_rule B with (nolock) ON A.CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id)
			when (SELECT top 1 count(1) FROM parent_level_v A with (nolock) inner JOIN contract_bus_card_rule B with (nolock) ON A.PARENT_CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id) > 0
		    then (SELECT top 1 PARENT_CONTRACT_ID FROM parent_level_v A inner JOIN contract_bus_card_rule B with (nolock) ON A.PARENT_CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id order by level_id desc)			
			else (select contract_id from party_contract_manu a with (nolock) inner join adm_bus_card_rule b on a.channel_id=b.channel_id where a.contract_id=pc.contract_id) end)derived_contract_id
from party_contract pc with (nolock)
inner join party_contract_manu pcm with (nolock) on pc.contract_id=pcm.contract_id and pcm.is_deleted_ind='N' and pcm.is_set_up_cmpltd_ind='N' where pc.is_deleted_ind='N')AA
left outer join contract_bus_card_rule cbc with (nolock) on aa.derived_contract_id=cbc.contract_id and cbc.is_deleted_ind='N'
left outer join adm_bus_card_rule abc on aa.channel_id=abc.channel_id and abc.is_deleted_ind='N';


-- dbo.card_level_contract_view source

---------------------------------------------


CREATE view card_level_contract_view as
select	AA.contract_id,contract_code,party_id,AA.channel_id,party_role_id,level_id,derived_contract_id,
		ISNULL(cbc.address_level_id,abc.address_level_id)address_level_id,
		(case when cbc.name_level_id is not null then cbc.phone_level_id else abc.phone_level_id end)phone_level_id,
		(case when cbc.name_level_id is not null then cbc.fax_level_id else abc.fax_level_id end)fax_level_id,
		(case when cbc.name_level_id is not null then cbc.email_level_id else abc.email_level_id end)email_level_id,
        ISNULL(cbc.name_level_id,abc.name_level_id)name_level_id,
        ISNULL(cbc.secondary_name_ind,abc.secondary_name_ind)secondary_name_ind,
        ISNULL(cbc.distributor_nm_ind,abc.distributor_nm_ind)distributor_nm_ind 
 from 
(select pc.contract_id,pcm.contract_code,pcm.party_id,pcm.channel_id,pc.party_role_id,pcm.level_id,(case when (select count(1) from party_contract A with (NOLOCK) inner JOIN contract_bus_card_rule B with (NOLOCK) ON A.CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id) > 0
		    then (select a.CONTRACT_ID from party_contract A with (NOLOCK) inner JOIN contract_bus_card_rule B with (NOLOCK) ON A.CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id)
			when (SELECT top 1 count(1) FROM parent_level_v A with (NOLOCK) inner JOIN contract_bus_card_rule B with (NOLOCK) ON A.PARENT_CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id) > 0
		    then (SELECT top 1 PARENT_CONTRACT_ID FROM parent_level_v A with (NOLOCK)  inner JOIN contract_bus_card_rule B with (NOLOCK) ON A.PARENT_CONTRACT_ID=B.CONTRACT_ID  WHERE A.CONTRACT_ID=pc.contract_id order by level_id desc)			
			else (select contract_id from party_contract_manu a with (NOLOCK) inner join adm_bus_card_rule b on a.channel_id=b.channel_id where a.contract_id=pc.contract_id) end)derived_contract_id
from party_contract pc with (NOLOCK) 
inner join party_contract_manu pcm with (NOLOCK) on pc.contract_id=pcm.contract_id)AA
left outer join contract_bus_card_rule cbc with (NOLOCK) on aa.derived_contract_id=cbc.contract_id
left outer join adm_bus_card_rule abc with (NOLOCK) on aa.channel_id=abc.channel_id;


-- dbo.code_search_view source

create view [code_search_view] as
select contract_id,contract_cd  from party_contract with (nolock) where contract_id in 
(select contract_id from party_contract_manu with (nolock) where  is_set_up_cmpltd_ind='N' and is_deleted_ind='N') 
and is_deleted_ind='N' 
union
select contract_id, contract_code as contract_cd from party_contract_manu with (nolock) where is_deleted_ind='N' and is_set_up_cmpltd_ind='N';


-- dbo.contract_contact_bcr_details source

------------------------------------------------------------------------------------------------------------------------------------------
CREATE View [contract_contact_bcr_details] AS
select a.contract_id as contractid,
 -- Party Address Id
(case when b.address_level_id=c.level_id then (select top 1 party_addr_id from bus_address_v  x with (NOLOCK) 
 where x.contract_id=a.contract_id) when b.address_level_id > c.level_id then (select top 1 party_addr_id from bus_address_v x with (NOLOCK)  where x.contract_id=a.contract_id) when b.address_level_id=100002 then	(select top 1 party_addr_id from party_addr a with (NOLOCK)
 left outer join adm_country b on a.country_id=b.country_id left outer join adm_state ast on a.state_id=ast.state_id 
 inner join adm_channel y on y.stage_channel_id =c.channel_id WHERE ((channel='DC' and a.addr_typ_id in (100004)) or (channel<>'DC' 
 and a.addr_typ_id in (100001,100003))) and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id) 
 when (select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id) is not null 
 then (select top 1 party_addr_id from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id 
 from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id)) 
 else (select top 1 party_addr_id from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id) end)party_addr_id,
-- Party Phone Id
(case when b.phone_level_id =c.level_id 
			then (select top 1 party_phn_id from phn_priority_v x
				  where x.CONTRACT_ID=a.contract_id)

			when b.phone_level_id > c.level_id  
			then (select top 1 party_phn_id from phn_priority_v x
				  where x.CONTRACT_ID=a.contract_id)

			when b.phone_level_id = 100002 
			then (select (case when ac.channel<>'DC' 
							   then (SELECT top 1 party_phn_id  FROM party_phn f WITH(NOLOCK)
									where f.party_id=cv.channel_id
									and f.is_deleted_ind='N' 
									and f.phn_typ_id in(100001,100002,100005,100006) 
									order by phn_typ_id,phn_loc_id)
						 else (select  TOP 1 party_phn_id from 
								(SELECT f.phn_typ_id,1 SNO,party_phn_id,phn_loc_id  FROM party_phn f WITH(NOLOCK)
										where  f.is_deleted_ind='N' and f.phn_typ_id in(100006) 
										and f.party_id=cv.channel_id
										union
										SELECT f.phn_typ_id,2 SNO,party_phn_id,phn_loc_id  FROM party_phn f WITH(NOLOCK)
										where  f.is_deleted_ind='N' and f.phn_typ_id in(100001,100002,100005) 
										and f.party_id=cv.channel_id)AA ORDER BY SNO,phn_loc_id)   end)party_phn_id
					from channel_view cv
					inner join adm_channel ac on cv.channel_id=ac.stage_channel_id
					where cv.channel_id=C.channel_id) 
			when (select top 1 parent_contract_id from parent_level_v 
				 where contract_id=a.contract_id and level_id=b.phone_level_id ) is not null 
			then (select top 1 c.party_phn_id from party_contract x with (NOLOCK) 
				 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
				 inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id 
							and bp.is_deleted_ind='N' 
				 inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id 
							and c.is_deleted_ind='N' --and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				 WHERE c.phn_typ_id in (100001,100002,100005,100006) 
				 and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v 
									where contract_id=a.contract_id and level_id=b.phone_level_id )) 
			else (select top 1 c.party_phn_id from party_contract x with (NOLOCK) 
				 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
				 inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N' 
				 inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id 
							and c.is_deleted_ind='N' --and (phn_cd not like 'HM%' or phn_cd not like 'OTH%') 
				 WHERE c.phn_typ_id in (100001,100002,100005,100006)
				 and x.CONTRACT_ID=a.contract_id) end)party_phn_id,
-- Party Fax Id
(case when b.fax_level_id =c.level_id 
			then (select top 1 party_phn_id from fax_priority_v x
				  where x.CONTRACT_ID=a.contract_id)

			when b.fax_level_id > c.level_id  
			then (select top 1 party_phn_id from fax_priority_v x
				  where x.CONTRACT_ID=a.contract_id)

			when b.fax_level_id = 100002 
			then (select (case when ac.channel<>'DC' 
							   then (SELECT top 1 party_phn_id  FROM party_phn f WITH(NOLOCK)
									where f.party_id=cv.channel_id
									and f.is_deleted_ind='N' 
									and f.phn_typ_id in(100003,100004,100007) 
									order by phn_typ_id,phn_loc_id)
						 else (select  TOP 1 party_phn_id from 
								(SELECT f.phn_typ_id,1 SNO,party_phn_id,phn_loc_id  FROM party_phn f WITH(NOLOCK)
										where  f.is_deleted_ind='N' and f.phn_typ_id in(100007) 
										and f.party_id=cv.channel_id
										union
										SELECT f.phn_typ_id,2 SNO,party_phn_id,phn_loc_id  FROM party_phn f WITH(NOLOCK)
										where  f.is_deleted_ind='N' and f.phn_typ_id in(100003,100004) 
										and f.party_id=cv.channel_id)AA ORDER BY SNO,phn_loc_id)   end)party_phn_id
					from channel_view cv
					inner join adm_channel ac on cv.channel_id=ac.stage_channel_id
					where cv.channel_id=C.channel_id) 
			when (select top 1 parent_contract_id from parent_level_v 
				 where contract_id=a.contract_id and level_id=b.fax_level_id ) is not null 
			then (select top 1 c.party_phn_id from party_contract x with (NOLOCK) 
				 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
				 inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id 
							and bp.is_deleted_ind='N' 
				 inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id 
							and c.is_deleted_ind='N' --and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				 WHERE c.phn_typ_id in (100003,100004,100007) 
				 and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v 
									where contract_id=a.contract_id and level_id=b.fax_level_id )) 
			else (select top 1 c.party_phn_id from party_contract x with (NOLOCK) 
				 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
				 inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N' 
				 inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id 
							and c.is_deleted_ind='N' --and (phn_cd not like 'HM%' or phn_cd not like 'OTH%') 
				 WHERE c.phn_typ_id in (100003,100004,100007)
				 and x.CONTRACT_ID=a.contract_id) end)party_fax_id,
-- Party Email Id
(case when b.email_level_id=c.level_id then (select top 1 b.party_internet_id from party_contract x with (NOLOCK) 
 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
 inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N' 
 inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%' 
 inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
 WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002))) 
 and x.CONTRACT_ID=a.contract_id) when b.email_level_id > c.level_id  then (select top 1  b.party_internet_id from party_contract x with (NOLOCK) 
 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
 inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N' 
 inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%' 
 inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
 WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002))) 
 and x.CONTRACT_ID=a.contract_id) when b.email_level_id = 100002  then (select  top 1 cc.party_internet_id from party_internet cc with (NOLOCK) 
 inner join adm_channel yy on yy.stage_channel_id =c.channel_id where cc.party_id=c.channel_id and cc.is_deleted_ind='N' and  cc.internet_cd not like 'OTH%' 
 and ((channel='DC' and cc.internet_typ_id in (100001)) or (channel<>'DC' and cc.internet_typ_id in (100002))) 
 order by cc.internet_typ_id) when (select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id= b.email_level_id ) is not null 
 then (select  top 1 bi.party_internet_id from party_contract x with (NOLOCK) 
 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
 inner join party_role_internet bi with (NOLOCK) on x.party_role_id=bi.party_role_id and bi.is_deleted_ind='N' 
 inner join party_internet c with (NOLOCK) on bi.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%' 
 inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
 WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002))) 
 and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id 
 and level_id= b.email_level_id )) else (select top 1 b.party_internet_id from party_contract x with (NOLOCK) 
 inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id 
 inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N' 
 inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' 
 and  internet_cd not like 'OTH%' inner join adm_channel y on pcm.channel_id=y.stage_channel_id WHERE ((channel='DC' 
 and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002))) 
 and x.CONTRACT_ID=a.contract_id)end)party_internet_id,
 c.party_id as partyid,c.contract_code,c.pcm_party_role_id,
c.level_id contract_level from party_contract a with (NOLOCK) inner join party_contract_manu c with (NOLOCK) 
 on a.contract_id=c.contract_id and c.is_deleted_ind='N' and c.is_set_up_cmpltd_ind='N'
 inner join card_level_contract_view b on a.contract_id=b.contract_id and a.is_deleted_ind='N';


-- dbo.contract_general_view source

CREATE VIEW [contract_general_view] as
SELECT     party_contract_manu.party_id, party_role_instance.party_role_id, party_contract_manu.ident, party_contract_manu.channel_id, 
                      party_contract_manu.branch_cd, party_contract.contract_id, party_contract.contract_status_id, party_contract.contract_type_id, 
                      party_contract_manu.status_change_reason_id, party_contract.contract_start_dtm, party_contract.contract_end_dtm, 
                      party_contract_manu.termination_reason_id, party_contract_manu.reporting_cont_contract_type_id, party_contract_manu.reporting_cont_cd, 
                      party_contract_manu.reporting_cont_change_reason_id, 
					  --party_contract_manu.payment_cont_cd,party_contract_manu.payment_cont_change_reason_id, 
					  party_contract_manu.tax_ind_id, contract_legacy_code.legacy_code, 
                      adm_contract_status.contract_status_cd, adm_contract_status.contract_status_nm, adm_contract_type.contract_type_nm, 
                      adm_contract_type.contract_type_cd, adm_levels.level_value, adm_levels.level_desc, adm_levels.level_number, adm_tax_indicator.tax_indicator, 
                      adm_code_status.code_status_cd, adm_code_status.code_status_nm, party.party_typ_id, adm_party_type.party_typ_nm, party.first_nm, 
                      party.last_nm, party.middle_nm, (case when party.party_typ_id=100002 then party.last_nm else null end)org_nm
FROM         adm_party_type INNER JOIN
                      party with (NOLOCK) ON adm_party_type.party_typ_id = party.party_typ_id 
					  --RIGHT OUTER JOIN party_name ON party_name.party_id = party.party_id 
					  INNER JOIN  party_contract with (NOLOCK)  INNER JOIN
                      adm_contract_status ON party_contract.contract_status_id = adm_contract_status.contract_status_id LEFT OUTER JOIN
                      adm_contract_type ON party_contract.contract_type_id = adm_contract_type.contract_type_id LEFT OUTER JOIN
                      party_role_instance with (NOLOCK) ON party_contract.party_role_id = party_role_instance.role_instance_id LEFT OUTER JOIN
                      party_contract_manu with (NOLOCK) ON party_contract.contract_id = party_contract_manu.contract_id ON 
                      party.party_id = party_contract_manu.party_id LEFT OUTER JOIN
                      adm_levels ON party_contract_manu.level_id = adm_levels.level_id LEFT OUTER JOIN
                      adm_tax_indicator ON party_contract_manu.tax_ind_id = adm_tax_indicator.tax_indicator_id LEFT OUTER JOIN
                      contract_legacy_code with (NOLOCK) ON party_contract.contract_id = contract_legacy_code.contract_id LEFT OUTER JOIN
                      adm_code_status ON contract_legacy_code.code_status_id = adm_code_status.code_status_id;


-- dbo.dataelementview source

CREATE  VIEW  [dataelementview] as

SELECT DISTINCT  data_element_t.*,rule_set_t.rule_set_nm FROM rule_set_t 
 INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
 INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
 INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id 
 INNER JOIN condition_detail_t ON rule_section_t.cond_id = condition_detail_t.cond_id 
 INNER JOIN data_element_t ON condition_detail_t.left_data_ele_id = data_element_t.data_ele_id OR  condition_detail_t.rght_data_ele_id = data_element_t.data_ele_id 
 INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd --WHERE (rule_set_t.rule_set_nm = 'FBA_RuleSet_Get_QuestionarrieSrcs') 
 union 
 SELECT DISTINCT data_element_t.*,rule_set_t.rule_set_nm FROM cond_data_map_t 
 INNER JOIN data_element_t ON cond_data_map_t.data_ele_id = data_element_t.data_ele_id 
 INNER JOIN condition_t ON cond_data_map_t.cond_id = condition_t.cond_id 
 INNER JOIN rule_set_t 
 INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
 INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
 INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id ON condition_t.cond_id = rule_section_t.cond_id 
 INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd --WHERE     (rule_set_t.rule_set_nm='FBA_RuleSet_Get_QuestionarrieSrcs')
 union 
 SELECT DISTINCT data_element_t.*,rule_set_t.rule_set_nm FROM         rule_set_t 
 INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
 INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
 INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id 
 INNER JOIN rule_section_resp_t ON rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_sect_seq_num = rule_section_resp_t.rule_sect_seq_num 
 INNER JOIN response_t ON rule_section_resp_t.resp_id = response_t.resp_id 
 INNER JOIN data_element_t ON response_t.data_ele_id = data_element_t.data_ele_id 
 INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd --WHERE     (rule_set_t.rule_set_nm='FBA_RuleSet_Get_QuestionarrieSrcs')
 union
 SELECT DISTINCT data_element_t.*,rule_set_t.rule_set_nm FROM         response_detail_t 
 INNER JOIN data_element_t ON response_detail_t.left_data_ele_id = data_element_t.data_ele_id OR response_detail_t.rght_data_ele_id = data_element_t.data_ele_id 
 INNER JOIN rule_set_t 
 INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
 INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
 INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id 
 INNER JOIN rule_section_resp_t ON rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_id = rule_section_resp_t.rule_id AND  rule_section_t.rule_sect_seq_num = rule_section_resp_t.rule_sect_seq_num ON response_detail_t.resp_id = rule_section_resp_t.resp_id 
 INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd --WHERE     (rule_set_t.rule_set_nm='FBA_RuleSet_Get_QuestionarrieSrcs')
 union 
SELECT DISTINCT data_element_t.*,rule_set_t.rule_set_nm FROM data_element_t 
 INNER JOIN resp_data_map_t ON data_element_t.data_ele_id = resp_data_map_t.data_ele_id 
 INNER JOIN rule_set_t 
 INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
 INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
 INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id 
 INNER JOIN rule_section_resp_t ON rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_sect_seq_num = rule_section_resp_t.rule_sect_seq_num ON resp_data_map_t.resp_id = rule_section_resp_t.resp_id 
 INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd --WHERE     (rule_set_t.rule_set_nm='FBA_RuleSet_Get_QuestionarrieSrcs')
union
SELECT DISTINCT data_element_t.*, rule_set_t.rule_set_nm AS Expr1
FROM data_element_t INNER JOIN resp_data_map_t ON data_element_t.data_ele_id = resp_data_map_t.data_ele_id 
INNER JOIN rule_set_t 
INNER JOIN rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id 
INNER JOIN rule_section_t ON rule_t.rule_id = rule_section_t.rule_id 
INNER JOIN rule_section_resp_t ON rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_id = rule_section_resp_t.rule_id AND rule_section_t.rule_sect_seq_num = rule_section_resp_t.rule_sect_seq_num 
ON resp_data_map_t.resp_id = rule_section_resp_t.resp_id 
INNER JOIN data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd 
INNER JOIN data_mapping_member_t ON data_element_t.data_ele_id = data_mapping_member_t.data_ele_id
union
SELECT DISTINCT data_element_t.*, rule_set_t.rule_set_nm AS Expr1
FROM data_element_t INNER JOIN
data_element_type_t ON data_element_t.data_elem_typ_cd = data_element_type_t.data_elem_typ_cd 
INNER JOIN event_mand_data_element_t ON data_element_t.data_ele_id = event_mand_data_element_t.data_ele_id 
CROSS JOIN rule_set_t INNER JOIN
rule_set_rules_t ON rule_set_t.rule_set_id = rule_set_rules_t.rule_set_id 
INNER JOIN rule_t ON rule_set_rules_t.rule_id = rule_t.rule_id;


