-- dbo.del_bus_address_v source

CREATE VIEW [del_bus_address_v] as  
select   
 a.contract_id,  
 pcm.level_id,  
 c.party_addr_id,  
 c.addr_typ_id,c.addr_id,  
 (ltrim(rtrim(coalesce(addr_line1,'')))+ltrim(rtrim(coalesce(isnull(addr_line2,''),'')))+','+ltrim(rtrim(coalesce(city,'')))+','+ltrim(rtrim(coalesce(country_nm,'')))+','+ltrim(rtrim  
 (coalesce(isnull(state_nm,other_state),'')))+','+ltrim(rtrim(coalesce(postal_cd,''))))  AS address ,   
 addr_line1,  
 addr_line2,  
 city,  
 country_nm,  
 isnull(state_nm,other_state) state,  
 postal_cd,  
 bad_addr_ind,  
 c.country_id,  
 isnull(c.state_id,'') state_id  ,
 case when state_nm is null then other_state else '' end other_state
   
from party_contract a with (nolock)    
inner join party_contract_manu pcm with (nolock) on pcm.contract_id=a.contract_id    
inner join party_role_addr b with (nolock) on a.party_role_id=b.party_role_id and b.is_deleted_ind='Y'    
inner join party_addr c with (nolock) on b.party_addr_id=c.party_addr_id and c.is_deleted_ind='N' and addr_id not like 'HM%'    
left outer join adm_country d on c.country_id=d.country_id    
left outer join adm_state e on c.state_id=e.state_id    
--added to get address based on channel - begin    
inner join adm_channel y on y.stage_channel_id =pcm.channel_id    
        WHERE ((channel='DC' and c.addr_typ_id in (100004)) or     
            (channel<>'DC' and c.addr_typ_id in (100001,100003)));


-- dbo.del_fax_priority_v source

CREATE view [del_fax_priority_v] AS
select ph.party_id,pp.contract_code,pp.contract_id,ph.party_phn_id,ph.phn_typ_id,
	   c.party_role_id,ph.phn_num,ph.extn_num,ph.phn_loc_id,ph.country_cd,ph.area_cd
from 
(select pcm.party_id,ac.channel,
		(case when channel<>'DC' 
			  then (SELECT top 1 phn_typ_id FROM party_phn f WITH(NOLOCK)
				inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
				inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
								   and pcm1.contract_code=pcm.contract_code 
								   and g.party_role_id=pcm1.pcm_party_role_id
				where  f.is_deleted_ind='N' 
				and f.phn_typ_id in(100003,100004,100007) 
				and f.party_id=pcm.party_id
				order by phn_loc_id ,phn_typ_id)
else (select  TOP 1 phn_typ_id from 
(SELECT f.phn_typ_id,1 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK)
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code 
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100007) 
		and f.party_id=pcm.party_id
		union all
		SELECT f.phn_typ_id,2 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK) 
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code  
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100003,100004) 
		and f.party_id=pcm.party_id)AA ORDER BY phn_loc_id,SNO)   end)priority_phn_typ_id,pcm.contract_code,pcm.contract_id,pcm.pcm_party_role_id
from party_contract_manu pcm WITH(NOLOCK)
inner join adm_channel ac  WITH(NOLOCK) on ac.stage_channel_id=pcm.channel_id 
)PP 
inner join party_phn ph WITH(NOLOCK) on pp.party_id=ph.party_id and pp.priority_phn_typ_id=ph.phn_typ_id and ph.is_deleted_ind='N' 
inner join PARTY_ROLE_PHN c WITH(NOLOCK) on ph.party_phn_id=c.party_phn_id and c.party_role_id=pp.pcm_party_role_id and c.is_deleted_ind='Y';


-- dbo.del_phn_priority_v source

CREATE view [del_phn_priority_v] AS
select ph.party_id,pp.contract_code,pp.contract_id,ph.party_phn_id,
		ph.phn_typ_id,c.party_role_id,ph.phn_num,ph.extn_num,ph.phn_loc_id,
		ph.country_cd,ph.area_cd
from 
(select pcm.party_id,ac.channel,
		(case when channel<>'DC' 
			  then (SELECT top 1 phn_typ_id FROM party_phn f WITH(NOLOCK)
				inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
				inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
								   and pcm1.contract_code=pcm.contract_code 
								   and g.party_role_id=pcm1.pcm_party_role_id
				where  f.is_deleted_ind='N' 
				and f.phn_typ_id in(100001,100002,100005,100006) 
				and f.party_id=pcm.party_id
				order by phn_loc_id ,phn_typ_id)
else (select  TOP 1 phn_typ_id from 
(SELECT f.phn_typ_id,1 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK)
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code 
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100006) 
		and f.party_id=pcm.party_id
		union all
		SELECT f.phn_typ_id,2 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK) 
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='Y' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code  
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100001,100002,100005) 
		and f.party_id=pcm.party_id)AA ORDER BY phn_loc_id,SNO)   end)priority_phn_typ_id,pcm.contract_code,pcm.contract_id,pcm.pcm_party_role_id
from party_contract_manu pcm WITH(NOLOCK)
inner join adm_channel ac  WITH(NOLOCK) on ac.stage_channel_id=pcm.channel_id 
)PP 
inner join party_phn ph WITH(NOLOCK) on pp.party_id=ph.party_id and pp.priority_phn_typ_id=ph.phn_typ_id and ph.is_deleted_ind='N' 
inner join PARTY_ROLE_PHN c WITH(NOLOCK) on ph.party_phn_id=c.party_phn_id and c.party_role_id=pp.pcm_party_role_id and c.is_deleted_ind='Y';


-- dbo.del_trans_bus_card_rule_info_v source

CREATE VIEW [del_trans_bus_card_rule_info_v] as
select 
	c.party_id as partyid,
	a.contract_id as contractid,
	c.contract_code,  
	b.address_level_id bus_card_level,
	c.level_id contract_level,  
	(case when b.address_level_id=c.level_id then (select top 1 addr_typ_id from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_typ_id from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)         	  when b.address_level_id=100002 then  
				 (select top 1 addr_typ_id from party_addr a with (NOLOCK)  						 
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)		   
		  else (select top 1 addr_typ_id from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_typ_id,-- 'Address Type',	 	
    (select top 1 addr_line3 from party_role_addr x with (NOLOCK) inner join party_addr y with (NOLOCK)  on x.party_addr_id=y.party_addr_id where x.party_role_id=a.party_role_id and y.addr_id not like 'HM%'and x.is_deleted_ind='Y')mailing_address,-- 'Additional MallingInfo',  
    (case when b.address_level_id=c.level_id then (select top 1 addr_line1 from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_line1 from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)     
		  when b.address_level_id=100002 then  
				 (select top 1 addr_line1 from party_addr a with (NOLOCK)  						 
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id  order by a.addr_typ_id)		   
		  else (select top 1 addr_line1 from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_line1 ,--as 'Address Line 1',	 
    (case when b.address_level_id=c.level_id then (select top 1 addr_line2 from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_line2 from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)     
		  when b.address_level_id=100002 then  
				 (select top 1 addr_line2 from party_addr a with (NOLOCK)  						
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 addr_line2 from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_line2 ,--as 'Address Line 2',
     (case when b.address_level_id=c.level_id then (select top 1 city from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 city from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 city	from party_addr a with (NOLOCK)  						
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 city from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) city,
	(case when b.address_level_id=c.level_id then (select top 1 country_id from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 country_id from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 country_id from party_addr a with (NOLOCK)  										
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 country_id from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) country_id,
	(case when b.address_level_id=c.level_id then (select top 1 state_id from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 state_id from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 state_id from party_addr a with (NOLOCK)  												
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 state_id from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) state_id ,--as 'State/Province',

----------------------other_state --begin

	(case when b.address_level_id=c.level_id then (select top 1 other_state from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 other_state from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 other_state from party_addr a with (NOLOCK)  												
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 other_state from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) other_state ,

-----------------------------------other_state --end

------------------------------- phone --begin
	(case when b.address_level_id=c.level_id then (select top 1 postal_cd from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 postal_cd from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 postal_cd from party_addr a with (NOLOCK)  											
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 postal_cd from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) postal_cd ,--as 'Zip/Postal',
	(case when b.address_level_id=c.level_id then (select top 1 bad_addr_ind from del_bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 bad_addr_ind from del_bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 bad_addr_ind from party_addr a with (NOLOCK)  											
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id order by a.addr_typ_id)  	  
		  else (select top 1 bad_addr_ind from del_bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
	  )) end) bad_addr_ind ,--as 'Address Validate Ind',
	(case when b.phone_level_id=c.level_id then (select top 1 phn_loc_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 phn_loc_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)	
          when b.phone_level_id = 100002  then (select  top 1 bb.phn_loc_id
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 phn_loc_id
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='Y'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) phn_loc_id ,--as 'Phone Location',
	(case when b.phone_level_id=c.level_id then (select top 1 phn_typ_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 phn_typ_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)					      
  
          when b.phone_level_id = 100002  then (select  top 1 bb.phn_typ_id
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 phn_typ_id
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='Y'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) phn_typ_id ,--as 'Phone Type Code',
	(case when b.phone_level_id=c.level_id then (select top 1 country_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 country_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
          when b.phone_level_id = 100002  then (select  top 1 bb.country_cd
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 country_cd
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='Y'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) country_cd ,--as 'Country Code',
	(case when b.phone_level_id=c.level_id then (select top 1 area_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 area_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
          when b.phone_level_id = 100002  then (select  top 1 bb.area_cd
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 area_cd
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='Y'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) area_cd ,--as 'Area Code',
	(case when b.phone_level_id=c.level_id then (select top 1 phn_num
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 phn_num
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='Y'
