                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, phn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                               adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
                          (SELECT     TOP 1 c.phn_num
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'Y' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) END) AS fax_num, 
                      (CASE WHEN b.fax_level_id = c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          del_fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id > c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          del_fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004, 100007)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100007) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
                          (SELECT     TOP 1 c.extn_num
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'Y' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) END) AS fax_extn_num
FROM         dbo.party_contract AS a WITH (NOLOCK) INNER JOIN
                      dbo.party_contract_manu AS c WITH (NOLOCK) ON a.contract_id = c.contract_id AND c.is_deleted_ind = 'Y' AND 
                      c.is_set_up_cmpltd_ind = 'N' INNER JOIN
                      dbo.card_level_contract_view AS b ON a.contract_id = b.contract_id
WHERE     (a.is_deleted_ind = 'Y');


-- dbo.fax_priority_v source

------------------------------------------------------------------------------------------------------------------------------------------
CREATE view [fax_priority_v] AS
select ph.party_id,pp.contract_code,pp.contract_id,ph.party_phn_id,ph.phn_typ_id,
	   c.party_role_id,ph.phn_num,ph.extn_num,ph.phn_loc_id,ph.country_cd,ph.area_cd
from 
(select pcm.party_id,ac.channel,
		(case when channel<>'DC' 
			  then (SELECT top 1 phn_typ_id FROM party_phn f WITH(NOLOCK)
				inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
				inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
								   and pcm1.contract_code=pcm.contract_code 
								   and g.party_role_id=pcm1.pcm_party_role_id
				where  f.is_deleted_ind='N' 
				and f.phn_typ_id in(100003,100004,100007) 
				and f.party_id=pcm.party_id
				order by phn_loc_id ,phn_typ_id)
else (select  TOP 1 phn_typ_id from 
(SELECT f.phn_typ_id,1 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK)
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code 
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100007) 
		and f.party_id=pcm.party_id
		union all
		SELECT f.phn_typ_id,2 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK) 
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code  
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100003,100004) 
		and f.party_id=pcm.party_id)AA ORDER BY phn_loc_id,SNO)   end)priority_phn_typ_id,pcm.contract_code,pcm.contract_id,pcm.pcm_party_role_id
from party_contract_manu pcm WITH(NOLOCK)
inner join adm_channel ac  WITH(NOLOCK) on ac.stage_channel_id=pcm.channel_id 
--where party_id=1000177508 and contract_code='109544' and pcm_party_role_id=426705
)PP 
inner join party_phn ph WITH(NOLOCK) on pp.party_id=ph.party_id and pp.priority_phn_typ_id=ph.phn_typ_id and ph.is_deleted_ind='N' 
inner join PARTY_ROLE_PHN c WITH(NOLOCK) on ph.party_phn_id=c.party_phn_id and c.party_role_id=pp.pcm_party_role_id and c.is_deleted_ind='N' 
--order by ph.phn_loc_id;


-- dbo.general_info_ind source

CREATE VIEW  [general_info_ind] as
SELECT     party.first_nm, party.last_nm, party.middle_nm,
(case when party_typ_id=100002 then party.last_nm else null end)org_nm,
--party_name.org_nm, 
party_other_name.other_nm, 
                      adm_marital_status.marital_status_nm, adm_designation.designation_nm, adm_gender.gender_nm, adm_salutation.salutation_nm, party.dob, 
                      party.deceased_ind,party.nick_nm,party.death_dt
FROM         party with (NOLOCK) --INNER JOIN
                      --party_name ON party.is_deleted_ind = 'N' and party.party_id = party_name.party_id and party_name.is_deleted_ind = 'N' 
                     LEFT OUTER JOIN
                      adm_salutation ON party.salutation_id = adm_salutation.salutation_id  and adm_salutation.is_deleted_ind = 'N' LEFT OUTER JOIN
                      adm_gender ON party.gender_id = adm_gender.gender_id and adm_gender.is_deleted_ind = 'N'  LEFT OUTER JOIN
                      adm_marital_status ON party.marital_status_id = adm_marital_status.marital_status_id and adm_marital_status.is_deleted_ind = 'N' INNER JOIN
                      party_other_name with (NOLOCK) ON party.party_id = party_other_name.party_id and party_other_name.is_deleted_ind = 'N' INNER JOIN
                      party_designation with (NOLOCK) ON party.party_id = party_designation.party_id and party_designation.is_deleted_ind = 'N' and party.is_deleted_ind = 'N' INNER JOIN
                      adm_designation ON party_designation.designation_id = adm_designation.designation_id and 
                      adm_designation.is_deleted_ind = 'N';


-- dbo.global_search_all source

CREATE VIEW  [dbo].[global_search_all] AS

select a.party_id,

a.party_typ_id,

--dbo.fn_GetRoleList(a.PARTY_ID)role_nm,

a.last_nm ,

a.first_nm,

a.middle_nm,

pcm.channel_id,

(select channel_desc from channel_view x  WITH(NOLOCK) where x.channel_id=pcm.channel_id)channel_desc,

--cv.channel_desc,

pca.branch_code,

pca.branch_name,

--(case when pcm.code_set_up_ind='I' then pcm.branch_cd when pcm.code_set_up_ind='B' then (select xp.branch_cd from party_contract_manu xp WITH(NOLOCK) where xp.contract_id=pcm.reporting_cont_cd  ) else null end)branch_code,

--(case when pcm.code_set_up_ind='I' then (select top 1 last_nm from party_contract_manu x WITH(NOLOCK) inner join party y WITH(NOLOCK) on x.party_id=y.party_id where x.contract_id=pcm.parent_contract_id and x.is_deleted_ind='N')

--        when (select xp.code_set_up_ind from party_contract_manu xp WITH(NOLOCK) where xp.contract_id=pcm.reporting_cont_cd )='B' then (select top 1 last_nm from party_contract_manu x WITH(NOLOCK) inner join party b WITH(NOLOCK) on x.party_id=b.party_id

--                                                                  where x.contract_id=pcm.reporting_cont_cd and x.is_deleted_ind='N') else null end)branch_name,

pcm.branch_cd,

pcm.region_cd ,         

pcm.contract_id,

pcm.pcm_contract_cd,

(case when  pcm.code_set_up_ind='R' then cast(pcm.region_cd as varchar)

      when  pcm.code_set_up_ind='B' then cast(pcm.branch_cd as varchar)

      else pcm.pcm_contract_cd end) selling_cd ,

pca.code_value,

pca.legacy_code,

--dbo.fn_getcodelist(pc.contract_id)code_value,

--dbo.fn_GetAttributeList(pc.contract_id)legacy_code,

g.contract_status_nm,

h.contract_type_cd+'-'+h.contract_type_nm as contracttype,

pcm.ident,

pca.other_code_value,

--(case when coalesce(dbo.fn_GetOtherCodevalueList(pc.contract_id),'') ='' then coalesce(dbo.fn_GetLegacyCodeList(pc.contract_id),'')

--      when coalesce(dbo.fn_GetLegacyCodeList(pc.contract_id),'')='' then coalesce(dbo.fn_GetOtherCodevalueList(pc.contract_id),'')

--      else dbo.fn_GetOtherCodevalueList(pc.contract_id)+','+dbo.fn_GetLegacyCodeList(pc.contract_id) end) other_code_value,

b.party_addr_id,

b.addr_line1,

b.addr_line2,

b.city,

d.state_id,

d.state_nm+'-'+d.state_cd as province,

postal_cd,

e.country_nm,

b.addr_id,

pcm.code_set_up_ind,

(case when pcm.contract_id is null then 'P' else 'C' end)flg,

pcm.pcm_party_role_id party_role_instance_id,

pr.party_role_id,

null addr_role_is_deleted_ind,

first_nm_clt, last_nm_clt , middle_nm_clt,

pcm_contract_type_id  , (select STUFF ((Select ', ' + LTRIM(RTRIM(license_num))from party_license_info l WITH(NOLOCK) where is_deleted_ind='N' and license_num != '' and s1.party_id=l.party_id for XML path ('')),1,1,'') as license_num from party_license_info s1 WITH(NOLOCK) where s1.party_id in (a.party_id ) group by s1.party_id) license_num,a.legal_business_name from party a WITH(NOLOCK)

left outer join party_addr b WITH(NOLOCK) on a.party_id=b.party_id  and b.is_deleted_ind='N'

left outer join party_contract_manu pcm WITH(NOLOCK) on a.party_id=pcm.party_id and pcm.is_set_up_cmpltd_ind='N' and  pcm.is_deleted_ind='N'

--left outer join party_contract pc WITH(NOLOCK) on pcm.contract_id=pc.contract_id and pc.is_deleted_ind='N'

left outer join party_role_instance pr WITH(NOLOCK) on pcm.pcm_party_role_id=pr.role_instance_id and pr.is_deleted_ind='N'

inner join party_contract_attr pca WITH(NOLOCK) on pcm.contract_id=pca.contract_id and b.party_id=pca.party_id and pcm.party_id=pca.party_id and  pca.addr_id=b.addr_id

--left outer join party_role_addr c WITH(NOLOCK) on pr.party_role_id=c.party_role_id and b.party_addr_id=c.party_addr_id  and c.is_deleted_ind='N'

left outer join adm_state d WITH(NOLOCK) on d.state_id=b.state_id and d.is_deleted_ind='N'

left outer join adm_country e WITH(NOLOCK) on e.country_id=b.country_id and e.is_deleted_ind='N'

--left outer join channel_view cv WITH(NOLOCK) on cv.channel_id=pcm.channel_id

left outer join adm_contract_status g WITH(NOLOCK) on g.contract_status_id=pcm.pcm_contract_status_id and g.is_deleted_ind='N'

left outer join adm_contract_type h WITH(NOLOCK) on h.contract_type_id=pcm.pcm_contract_type_id and h.is_deleted_ind='N'

where a.is_deleted_ind='N';


-- dbo.global_search_contract source

CREATE VIEW [global_search_contract] as
select	a.party_id,
		p.party_typ_id,
		dbo.fn_GetRoleList(a.PARTY_ID)role_nm,
		p.last_nm last_nm,p.first_nm,
		a.channel_id,
		cv.channel_desc,
		(case when a.code_set_up_ind='I' then a.branch_cd else null end)branch_code, 
		(case when a.code_set_up_ind='I' then (select top 1 last_nm from party_contract_manu x with (NOLOCK) inner join party b with (NOLOCK) on x.party_id=b.party_id where x.branch_cd=a.branch_cd and code_set_up_ind='B' and x.is_deleted_ind='N') else null end)branch_name,
		--(case when a.code_set_up_ind='R' then a.region_cd else null end)region_cd, 	
		a.branch_cd,
		a.region_cd , 		
		a.contract_id, 
		b.contract_cd,
		(case when  a.code_set_up_ind='R' then cast(a.region_cd as varchar)
			  when  a.code_set_up_ind='B' then cast(a.branch_cd as varchar) 
			  else b.contract_cd end) selling_cd ,
		dbo.fn_getcodelist(a.contract_id)code_value,
		dbo.fn_GetAttributeList(a.contract_id)legacy_code,
		j.contract_status_nm,
		l.contract_type_cd+'-'+l.contract_type_nm as contracttype,
		a.ident,
		--null code_typ_id, 
		(case when coalesce(dbo.fn_GetOtherCodevalueList(a.contract_id),'') ='' then coalesce(dbo.fn_GetLegacyCodeList(a.contract_id),'')
			 when coalesce(dbo.fn_GetLegacyCodeList(a.contract_id),'')='' then coalesce(dbo.fn_GetOtherCodevalueList(a.contract_id),'')
			 else dbo.fn_GetOtherCodevalueList(a.contract_id)+','+dbo.fn_GetLegacyCodeList(a.contract_id) end) other_code_value,
		d.addr_line1, 
		d.addr_line2, 
		d.city, 
		e.state_id, 
		e.state_nm+'-'+e.state_cd as province,
		d.postal_cd, 
		m.country_nm,
		a.code_set_up_ind
from party_contract_manu a with (NOLOCK) 
inner join party_contract b with (NOLOCK) on a.contract_id=b.contract_id 
inner join party p with (NOLOCK) on a.party_id=p.party_id 
--left outer join party_name c on a.party_id=c.party_id and c.is_deleted_ind='N' 
left outer join party_role_addr n with (NOLOCK) on b.party_role_id=n.party_role_id  
left outer join party_addr d with (NOLOCK) on a.party_id=d.party_id and n.party_addr_id=d.party_addr_id and d.is_deleted_ind='N'
left outer join adm_state e on d.state_id=e.state_id and e.is_deleted_ind='N'
left outer join adm_contract_status j on j.contract_status_id=b.contract_status_id and j.is_deleted_ind='N' 
left outer join adm_country m on m.country_id=d.country_id and m.is_deleted_ind='N'
left outer join adm_contract_type l on b.contract_type_id=l.contract_type_id and l.is_deleted_ind='N'
left outer join channel_view cv on cv.channel_id=a.channel_id
where a.is_deleted_ind='N' and b.is_deleted_ind='N' and p.is_deleted_ind='N'
and is_set_up_cmpltd_ind='N';


-- dbo.global_search_party source

CREATE VIEW [global_search_party] as
select	a.party_id,
		a.party_typ_id,
		dbo.fn_GetRoleList(a.PARTY_ID)role_nm,
		a.last_nm ,a.first_nm,
		null channel_id,
		null channel_desc,
		null branch_cd, 
		null branch_name, 
		null contract_id, 
		null contract_cd,
		null code_value, 
		null contract_status_nm,
		null contracttype,
		null ident,
		null code_typ_id, 
		null other_code_value, 
		d.addr_line1, 
		d.addr_line2, 
		d.city, 
		e.state_id, 
		e.state_nm+'-'+e.state_cd as province,
		d.postal_cd, 
		m.country_nm
from party a with (NOLOCK)
left outer join party_addr d with (NOLOCK) on a.party_id=d.party_id and d.is_deleted_ind='N'
left outer join adm_state e on d.state_id=e.state_id and e.is_deleted_ind='N'
left outer join adm_country m on m.country_id=d.country_id and m.is_deleted_ind='N'
where a.is_deleted_ind='N';


