-- dbo.non_con_relationship_view source

CREATE view non_con_relationship_view as
  
select pri.party_id,pcma.channel_id from_Channel,pcmb.channel_id to_Channel,cast(prn.relationship_id as varchar) relationship_id,   
(select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +   
coalesce(party.middle_nm,'') as frompartyname from party with (nolock) where party.party_id=prn.from_party_id)   
as frompartyname, (select adm_party_role.party_role_nm from party_role_instance with (nolock)  
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
where party_role_instance.role_instance_id = prn.party_a_role_id and party_role_instance.party_id=pri.party_id) as frompartyrole,   
prn.party_lvl_from_ind as from_lvl_ind,  
(case when pcma.code_set_up_ind ='I' then pca.contract_cd   
when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar)   
when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end)   
AS FROM_CODE,(case when pcmb.code_set_up_ind ='I' then pcb.contract_cd   
when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar)   
when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE,   
prn.to_party_id as topartyid, (select coalesce(party.last_nm,'') + ' ' +   
coalesce(party.first_nm,'') + ' ' + coalesce(party.middle_nm,'') as frompartyname   
from party with (NOLOCK) where party.party_id=prn.to_party_id) as topartyname,   
(select  adm_party_role.party_role_nm from party_role_instance with (NOLOCK)    
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
where party_role_instance.role_instance_id = prn.party_b_role_id and prn.to_party_id=party_role_instance.party_id)   
as topartyrole, 
(select title from party p where p.party_id=prn.to_party_id and is_deleted_ind='N') as title,
prn.party_lvl_to_ind as to_lvl_ind, prn.relationship_status, null as inhrdfrompartyid, null as inhrdfrompartyname   
from party_relationship_ncr prn with (NOLOCK)   
inner join party_role_instance pri with (NOLOCK) on prn.party_a_role_id = pri.role_instance_id and pri.is_deleted_ind='N'    
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=prn.party_a_role_id and pca.is_deleted_ind='N'   
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N'   
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=prn.party_b_role_id and pcb.is_deleted_ind='N'   
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N'   
where  prn.is_deleted_ind='N'
union   
select pcm.party_id,pcm.channel_id from_Channel,pcmb.channel_id to_Channel, cast(prn.relationship_id as varchar)+'I'+cast(pri.role_instance_id as varchar) relationship_id,  
  (select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +coalesce(party.middle_nm,'') as frompartyname   
   from party where party.party_id=pcm.party_id) as frompartynm,  
  (select adm_party_role.party_role_nm from party_role_instance with (nolock)  
   inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
  where party_role_instance.role_instance_id = pri.role_instance_id and party_role_instance.party_id=pcm.party_id) as frompartyrole,  
     null as from_lvl_ind,  
  (case when pcma.code_set_up_ind ='I' then pca.contract_cd   
     when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar)   
     when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end) AS FROM_CODE,  
  (case when pcmb.code_set_up_ind ='I' then pcb.contract_cd   
     when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar)   
     when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE,  
  prn.to_party_id as topartyid,  
  (select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' + coalesce(party.middle_nm,'') as frompartyname   
   from party with (nolock) where party.party_id=prn.to_party_id) as topartyname,  
  (select adm_party_role.party_role_nm from party_role_instance with (nolock)  
   inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
   where party_role_instance.role_instance_id = prn.party_b_role_id and prn.to_party_id=party_role_instance.party_id) as topartyrole,  
	(select title from party p where p.party_id=prn.to_party_id and is_deleted_ind='N') as title,
   null as to_lvl_ind,  
  prn.relationship_status,  
  prn.from_party_id as inhrdfrompartyid,  
  (select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +coalesce(party.middle_nm,'') from party where party_id=prn.from_party_id) as inhrdfrompartyname   
from party_contract_manu pcm with (NOLOCK)   
inner join party_contract pc with (NOLOCK) on pc.contract_id=pcm.contract_id and  pc.is_deleted_ind='N'   
inner join parent_role_instances pri with (NOLOCK) on pri.role_instance_id = pc.party_role_id   
inner join party_relationship_ncr prn with (NOLOCK) on prn.party_a_role_id = pri.parent_role_instance_id and prn.inheritable_ind = 'Y' and prn.is_deleted_ind='N'   
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=pri.role_instance_id and pca.is_deleted_ind='N'   
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N'   
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=prn.party_b_role_id and pcb.is_deleted_ind='N'   
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N'   
where  pcm.is_deleted_ind='N' and pcm.is_set_up_cmpltd_ind='N'  
union   
select prn.from_party_id party_id,pcma.channel_id from_Channel,pcmb.channel_id to_Channel,cast(prn.relationship_id as varchar)+'I'+cast(pri.role_instance_id as varchar)+'B'   
relationship_id,(select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +   
coalesce(party.middle_nm,'') as frompartyname from party with (nolock)  
where party.party_id=prn.from_party_id) as frompartynm,  
(select adm_party_role.party_role_nm from party_role_instance with (NOLOCK)    
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
where party_role_instance.role_instance_id = prn.party_a_role_id   
and party_role_instance.party_id=prn.from_party_id) as frompartyrole,  
null as from_lvl_ind,  
(case when pcma.code_set_up_ind ='I' then pca.contract_cd   
when pcma.code_set_up_ind ='B' then cast(pcma.branch_cd as varchar)   
when pcma.code_set_up_ind ='R' then cast(pcma.region_cd as varchar) end)   
AS FROM_CODE,(case when pcmb.code_set_up_ind ='I' then pcb.contract_cd   
when pcmb.code_set_up_ind ='B' then cast(pcmb.branch_cd as varchar)   
when pcmb.code_set_up_ind ='R' then cast(pcmb.region_cd as varchar) end) AS TO_CODE,  
(select party_id from party_role_instance pr where pr.role_instance_id=pri.role_instance_id)   
as topartyid,(select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +   
coalesce(party.middle_nm,'') as frompartyname from party with (NOLOCK)   
inner join party_role_instance with (nolock) on party_role_instance.role_instance_id=pri.role_instance_id   
where party.party_id=party_role_instance.party_id) as topartyname,  
(select  top (1) adm_party_role.party_role_nm from party_role_instance with (NOLOCK)   
inner join adm_party_role on party_role_instance.party_role_id = adm_party_role.party_role_id   
where (party_role_instance.role_instance_id = pri.role_instance_id))   
as topartyrole,
(select title from party p where p.party_id=(select party_id from party_role_instance pr where pr.role_instance_id=pri.role_instance_id and is_deleted_ind='N') and is_deleted_ind='N') as title,
null as to_lvl_ind,prn.relationship_status,prn.to_party_id as inhrdfrompartyid,  
  (select coalesce(party.last_nm,'') + ' ' + coalesce(party.first_nm,'') + ' ' +coalesce(party.middle_nm,'') from party where party_id=prn.to_party_id) as inhrdfrompartyname    
from party_relationship_ncr prn with (NOLOCK)   
inner join party_contract pc with (NOLOCK) on pc.party_role_id=prn.party_b_role_id and pc.is_deleted_ind='N'   
inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=pc.contract_id and pcm.is_deleted_ind='N' and is_set_up_cmpltd_ind='N'   
inner join parent_role_instances pri with (NOLOCK) on pri.parent_role_instance_id = pc.party_role_id and prn.party_b_role_id = pri.parent_role_instance_id  and is_set_up_cmpltd_ind='N'   
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=prn.party_a_role_id and pca.is_deleted_ind='N'   
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N'   
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=pri.role_instance_id and pcb.is_deleted_ind='N'   
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N'   
where prn.inheritable_ind = 'Y' and prn.is_deleted_ind='N';


-- dbo.parent_level_v source

/****** Object:  View [parent_level_v]    Script Date: 07/14/2009 12:44:17 ******/


CREATE VIEW [parent_level_v] as 
select contract_id,role_instance_id, parent_contract_id,party_id parent_party_id,parent_role_instance_id,level_depth,level_id from (select a.contract_id,role_instance_id,c.contract_id parent_contract_id,e.party_id,b.parent_role_instance_id,b.level_depth,e.level_id
from party_contract a with (NOLOCK) 
inner join parent_role_instances b with (NOLOCK) on a.party_role_id=b.role_instance_id
inner join party_contract c with (NOLOCK) on b.parent_role_instance_id=c.party_role_id
inner join party_contract_manu e with (NOLOCK) on c.contract_id=e.contract_id  where  a.is_deleted_ind='N')AA
where level_id is not null;


-- dbo.phn_priority_v source

CREATE view [phn_priority_v] AS
select ph.party_id,pp.contract_code,pp.contract_id,ph.party_phn_id,
		ph.phn_typ_id,c.party_role_id,ph.phn_num,ph.extn_num,ph.phn_loc_id,
		ph.country_cd,ph.area_cd
from 
(select pcm.party_id,ac.channel,
		(case when channel<>'DC' 
			  then (SELECT top 1 phn_typ_id FROM party_phn f WITH(NOLOCK)
				inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
				inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
								   and pcm1.contract_code=pcm.contract_code 
								   and g.party_role_id=pcm1.pcm_party_role_id
				where  f.is_deleted_ind='N' 
				and f.phn_typ_id in(100001,100002,100005,100006) 
				and f.party_id=pcm.party_id
				order by phn_loc_id ,phn_typ_id)
else (select  TOP 1 phn_typ_id from 
(SELECT f.phn_typ_id,1 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK)
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code 
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100006) 
		and f.party_id=pcm.party_id
		union all
		SELECT f.phn_typ_id,2 SNO,phn_loc_id FROM party_phn f WITH(NOLOCK) 
		inner join PARTY_ROLE_PHN g WITH(NOLOCK) on f.party_phn_id=g.party_phn_id and g.is_deleted_ind='N' 
		inner join party_contract_manu pcm1 WITH(NOLOCK) on pcm1.party_id=f.party_id 
		and pcm1.contract_code=pcm.contract_code  
		and g.party_role_id=pcm1.pcm_party_role_id
		where  f.is_deleted_ind='N' and f.phn_typ_id in(100001,100002,100005) 
		and f.party_id=pcm.party_id)AA ORDER BY phn_loc_id,SNO)   end)priority_phn_typ_id,pcm.contract_code,pcm.contract_id,pcm.pcm_party_role_id
from party_contract_manu pcm WITH(NOLOCK)
inner join adm_channel ac  WITH(NOLOCK) on ac.stage_channel_id=pcm.channel_id 
--where pcm.party_id=1000160741 and pcm.contract_code='109538' 
)PP 
inner join party_phn ph WITH(NOLOCK) on pp.party_id=ph.party_id and pp.priority_phn_typ_id=ph.phn_typ_id and ph.is_deleted_ind='N' 
inner join PARTY_ROLE_PHN c WITH(NOLOCK) on ph.party_phn_id=c.party_phn_id and c.party_role_id=pp.pcm_party_role_id and c.is_deleted_ind='N';


-- dbo.relationship_channel_security_user source

CREATE VIEW [relationship_channel_security_user] as
select a.party_a_role_id,b.party_id from_party_id,d.channel_id from_channel_id,
a.party_b_role_id,e.party_id to_party_id,g.channel_id to_channel_id 
from party_relationship_ncr a with (NOLOCK) 
left outer join party_role_instance b with (NOLOCK) on a.party_a_role_id=b.role_instance_id and b.is_deleted_ind='N'
left outer join party_contract c with (NOLOCK) on b.role_instance_id=c.party_role_id and c.is_deleted_ind='N'
left outer join party_contract_manu d with (NOLOCK) on c.contract_id=d.contract_id and d.is_deleted_ind='N' and d.is_set_up_cmpltd_ind ='N'
left outer join party_role_instance e with (NOLOCK) on a.party_b_role_id=e.role_instance_id and e.is_deleted_ind='N'
left outer join party_contract f with (NOLOCK) on e.role_instance_id=f.party_role_id and f.is_deleted_ind='N'
left outer join party_contract_manu g with (NOLOCK) on f.contract_id=g.contract_id and g.is_deleted_ind='N' and g.is_set_up_cmpltd_ind ='N'
where a.is_deleted_ind='N' 
union
select a.party_a_role_id,e.party_id from_party_id,d.channel_id from_channel_id,
a.party_b_role_id,b.party_id to_party_id,g.channel_id to_channel_id 
from party_relationship_ncr a with (NOLOCK) 
left outer join party_role_instance b with (NOLOCK) on a.party_a_role_id=b.role_instance_id and b.is_deleted_ind='N'
left outer join party_contract c with (NOLOCK) on b.role_instance_id=c.party_role_id and c.is_deleted_ind='N'
left outer join party_contract_manu d with (NOLOCK) on c.contract_id=d.contract_id and d.is_deleted_ind='N' and d.is_set_up_cmpltd_ind ='N'
left outer join party_role_instance e with (NOLOCK) on a.party_b_role_id=e.role_instance_id and e.is_deleted_ind='N'
left outer join party_contract f with (NOLOCK) on e.role_instance_id=f.party_role_id and f.is_deleted_ind='N'
left outer join party_contract_manu g with (NOLOCK) on f.contract_id=g.contract_id and g.is_deleted_ind='N' and g.is_set_up_cmpltd_ind ='N'
where a.is_deleted_ind='N' 
union
select prn.party_a_role_id,(select party_id from party_role_instance pr where pr.role_instance_id=pri.role_instance_id)
from_party_id,
pcma.channel_id from_channel_id,
prn.party_b_role_id,prn.from_party_id to_party_id,
pcmb.channel_id to_channel_id 
from party_relationship_ncr prn with (NOLOCK) 
inner join party_contract pc with (NOLOCK) on pc.party_role_id=prn.party_b_role_id and pc.is_deleted_ind='N' 
inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=pc.contract_id and pcm.is_deleted_ind='N' and is_set_up_cmpltd_ind='N' 
inner join parent_role_instances pri with (NOLOCK) on pri.parent_role_instance_id = pc.party_role_id and (prn.party_b_role_id = pri.parent_role_instance_id and prn.inheritable_ind = 'Y' 
and prn.is_deleted_ind='N') and pc.is_deleted_ind='N' and is_set_up_cmpltd_ind='N' 
left outer join party_contract pca with (NOLOCK) on pca.party_role_id=prn.party_a_role_id and pca.is_deleted_ind='N' 
left outer join party_contract_manu pcma with (NOLOCK) on pcma.contract_id=pca.contract_id and pcma.is_deleted_ind='N' and pcma.is_set_up_cmpltd_ind='N' 
left outer join party_contract pcb with (NOLOCK) on pcb.party_role_id=pri.role_instance_id and pcb.is_deleted_ind='N' 
left outer join party_contract_manu pcmb with (NOLOCK) on pcmb.contract_id=pcb.contract_id and pcmb.is_deleted_ind='N' and pcmb.is_set_up_cmpltd_ind='N'
where prn.is_deleted_ind='N';


-- dbo.relationship_channel_view_1 source

CREATE VIEW [relationship_channel_view_1] as
select b.party_id,a.channel_id,b.role_instance_id,c.party_b_role_id,d.party_id to_party_id,e.channel_id to_channel_id
from party_contract_manu a with (NOLOCK) 
inner join party_role_instance b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N'
inner join party_relationship c with (NOLOCK) on b.role_instance_id=c.party_a_role_id and c.is_deleted_ind='N'
inner join party_role_instance d with (NOLOCK) on c.party_b_role_id=d.role_instance_id and d.is_deleted_ind='N'
left outer join party_contract_manu e with (NOLOCK) on d.party_id=e.party_id and e.is_deleted_ind='N'
where a.channel_id <> d.party_id
and e.channel_id is null
union
select b.party_id,a.channel_id,b.role_instance_id,c.party_a_role_id,d.party_id to_party_id,e.channel_id to_channel_id
from party_contract_manu a with (NOLOCK) 
inner join party_role_instance b with (NOLOCK) on a.party_id=b.party_id and b.is_deleted_ind='N'
inner join party_relationship c with (NOLOCK) on b.role_instance_id=c.party_b_role_id and c.is_deleted_ind='N'
inner join party_role_instance d with (NOLOCK) on c.party_a_role_id=d.role_instance_id and d.is_deleted_ind='N'
left outer join party_contract_manu e with (NOLOCK) on d.party_id=e.party_id and e.is_deleted_ind='N'
where  a.channel_id <> d.party_id
and e.channel_id is null;


-- dbo.roles_view source

CREATE VIEW  [roles_view] as
SELECT     adm_party_role.party_role_nm, adm_party_role_status.role_status_cd, 
party_role.start_dtm, party_role.end_dtm
FROM   party_role with (NOLOCK) INNER JOIN
adm_party_role ON party_role.is_deleted_ind = 'N' and party_role.party_role_id = adm_party_role.party_role_id and adm_party_role.is_deleted_ind = 'N'
INNER JOIN  adm_party_role_status ON party_role.role_status_id = adm_party_role_status.role_status_id  and adm_party_role_status.is_deleted_ind = 'N';


