-- dbo.sysextendedarticlesview source

create view dbo.sysextendedarticlesview
               as
               select artid, creation_script, del_cmd, description,
        	dest_table, filter, filter_clause, ins_cmd, name, objid, pubid,
        	pre_creation_cmd, status, sync_objid, type, upd_cmd,
        	schema_option, dest_owner, ins_scripting_proc, del_scripting_proc,
        	upd_scripting_proc, custom_script, fire_triggers_on_snapshot
               from sysarticles
               union all
               select artid, creation_script, NULL, description,
               dest_object, NULL, NULL, NULL, name, objid, pubid, 
               pre_creation_cmd, status, NULL, type, NULL, 
               schema_option, dest_owner, NULL, NULL, NULL, NULL, 0
               from sysschemaarticles
               go;


-- dbo.trans_bus_card_rule_info_v source

CREATE VIEW [trans_bus_card_rule_info_v] as
select 
	c.party_id as partyid,
	a.contract_id as contractid,
	c.contract_code,  
	b.address_level_id bus_card_level,
	c.level_id contract_level,  
	(case when b.address_level_id=c.level_id then (select top 1 addr_typ_id from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_typ_id from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)         	  when b.address_level_id=100002 then  
				 (select top 1 addr_typ_id from party_addr a with (NOLOCK)  						 
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)		   
		  else (select top 1 addr_typ_id from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_typ_id,-- 'Address Type',	 	
    (select top 1 addr_line3 from party_role_addr x with (NOLOCK) inner join party_addr y with (NOLOCK)  on x.party_addr_id=y.party_addr_id where x.party_role_id=a.party_role_id and y.addr_id not like 'HM%'and x.is_deleted_ind='N')mailing_address,-- 'Additional MallingInfo',  
    (case when b.address_level_id=c.level_id then (select top 1 addr_line1 from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_line1 from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)     
		  when b.address_level_id=100002 then  
				 (select top 1 addr_line1 from party_addr a with (NOLOCK)  						 
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)		   
		  else (select top 1 addr_line1 from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_line1 ,--as 'Address Line 1',	 
    (case when b.address_level_id=c.level_id then (select top 1 addr_line2 from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 addr_line2 from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)     
		  when b.address_level_id=100002 then  
				 (select top 1 addr_line2 from party_addr a with (NOLOCK)  						
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 addr_line2 from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end)addr_line2 ,--as 'Address Line 2',
     (case when b.address_level_id=c.level_id then (select top 1 city from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 city from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 city	from party_addr a with (NOLOCK)  						
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 city from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) city,
	(case when b.address_level_id=c.level_id then (select top 1 country_id from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 country_id from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 country_id from party_addr a with (NOLOCK)  										
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 country_id from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) country_id,
	(case when b.address_level_id=c.level_id then (select top 1 state_id from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 state_id from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 state_id from party_addr a with (NOLOCK)  												
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 state_id from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) state_id ,--as 'State/Province',

----------------------other_state --begin

	(case when b.address_level_id=c.level_id then (select top 1 other_state from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 other_state from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 other_state from party_addr a with (NOLOCK)  												
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 other_state from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) other_state ,

-----------------------------------other_state --end

------------------------------- phone --begin
	(case when b.address_level_id=c.level_id then (select top 1 postal_cd from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 postal_cd from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 postal_cd from party_addr a with (NOLOCK)  											
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 postal_cd from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
      )) end) postal_cd ,--as 'Zip/Postal',
	(case when b.address_level_id=c.level_id then (select top 1 bad_addr_ind from bus_address_v  x with (NOLOCK) where x.contract_id=a.contract_id) 
		  when b.address_level_id > c.level_id  then (select top 1 bad_addr_ind from bus_address_v x with (NOLOCK) where x.contract_id=a.contract_id)      
		  when b.address_level_id=100002 then  
				 (select top 1 bad_addr_ind from party_addr a with (NOLOCK)  											
						inner join adm_channel y on y.stage_channel_id =c.channel_id  
						WHERE ((channel='DC' and a.addr_typ_id in (100004)) or   
							(channel<>'DC' and a.addr_typ_id in (100001,100003)))  
						and a.party_id=c.channel_id and a.is_deleted_ind='N' order by a.addr_typ_id)  	  
		  else (select top 1 bad_addr_ind from bus_address_v x with (NOLOCK) where x.contract_id=(select top 1 parent_contract_id from parent_level_v with (NOLOCK) where contract_id=a.contract_id and level_id=b.address_level_id--order by level_depth  
	  )) end) bad_addr_ind ,--as 'Address Validate Ind',
	(case when b.phone_level_id=c.level_id then (select top 1 phn_loc_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 phn_loc_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)	
          when b.phone_level_id = 100002  then (select  top 1 bb.phn_loc_id
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 phn_loc_id
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='N'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) phn_loc_id ,--as 'Phone Location',
	(case when b.phone_level_id=c.level_id then (select top 1 phn_typ_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 phn_typ_id
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)					      
  
          when b.phone_level_id = 100002  then (select  top 1 bb.phn_typ_id
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100001,100002,100005) order by bb.phn_typ_id)
          else (select top 1 phn_typ_id
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='N'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100001,100002,100005)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.phone_level_id--order by level_depth
    )) end) phn_typ_id ,--as 'Phone Type Code',
	(case when b.phone_level_id=c.level_id then (select top 1 country_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
		  when b.phone_level_id > c.level_id  then (select top 1 country_cd
													from party_contract x with (NOLOCK)
													inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
													inner join party_role_phn b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
													inner join party_phn c with (NOLOCK) on b.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
													WHERE c.phn_typ_id in (100001,100002,100005)
													and x.contract_id=a.contract_id)
          when b.phone_level_id = 100002  then (select  top 1 bb.country_cd
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
