													WHERE c.phn_typ_id in (100003,100004)
													and x.contract_id=a.contract_id)
          when b.fax_level_id = 100002  then (select  top 1 bb.extn_num
													from party_phn bb with (NOLOCK)
													inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
													where bb.party_id=c.channel_id and bb.is_deleted_ind='N' 
													and (bb.phn_cd not like 'HM%' or bb.phn_cd not like 'OTH%') 
													and bb.phn_typ_id in (100003,100004) order by bb.phn_typ_id)
          else (select top 1 extn_num
				from party_contract x with (NOLOCK)
				inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
				inner join party_role_phn bp with (NOLOCK) on x.party_role_id=bp.party_role_id and bp.is_deleted_ind='N'
				inner join party_phn c with (NOLOCK) on bp.party_phn_id=c.party_phn_id and c.is_deleted_ind='N' and (phn_cd not like 'HM%' or phn_cd not like 'OTH%')
				WHERE c.phn_typ_id in (100003,100004)
				and x.contract_id=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.fax_level_id--order by level_depth
    )) end) fax_extn_num ,--as 'Ext',
		

--------------------------------- fax --end
	(case when b.email_level_id=c.level_id then (select top 1 internet_typ_id
														from party_contract x with (NOLOCK) 
														inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
														inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
														inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
														inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
														WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
														and x.CONTRACT_ID=a.contract_id)
	      when b.email_level_id > c.level_id  then (select top 1  internet_typ_id
														from party_contract x with (NOLOCK) 
														inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
														inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
														inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
														inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
														WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
														and x.CONTRACT_ID=a.contract_id)			
              ---added channel level email begin
          when b.email_level_id = 100002  then (select  top 1 cc.internet_typ_id from party_internet cc with (NOLOCK) 
                                 inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                 where cc.party_id=c.channel_id and cc.is_deleted_ind='N' and  cc.internet_cd not like 'OTH%' 
                                 and ((channel='DC' and cc.internet_typ_id in (100001)) or (channel<>'DC' and cc.internet_typ_id in (100002)))
                                 order by cc.internet_typ_id)
              ---added channel level email end
          else (select  top 1 internet_typ_id
						from party_contract x with (NOLOCK) 
						inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
						inner join party_role_internet bi with (NOLOCK) on x.party_role_id=bi.party_role_id and bi.is_deleted_ind='N'
						inner join party_internet c with (NOLOCK) on bi.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
						inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
						WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
						and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.email_level_id--order by level_depth
	)) end)internet_typ_id ,--as 'EMail Type',
	(case when b.email_level_id=c.level_id then (select top 1 party_email
														from party_contract x with (NOLOCK) 
														inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
														inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
														inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
														inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
														WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
														and x.CONTRACT_ID=a.contract_id)
	      when b.email_level_id > c.level_id  then (select top 1  party_email
														from party_contract x with (NOLOCK) 
														inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
														inner join party_role_internet b with (NOLOCK) on x.party_role_id=b.party_role_id and b.is_deleted_ind='N'
														inner join party_internet c with (NOLOCK) on b.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
														inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
														WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
														and x.CONTRACT_ID=a.contract_id)	
              ---added channel level email begin
          when b.email_level_id = 100002  then (select  top 1 cc.party_email from party_internet cc with (NOLOCK) 
                                 inner join adm_channel yy on yy.stage_channel_id =c.channel_id 
                                 where cc.party_id=c.channel_id and cc.is_deleted_ind='N' and  cc.internet_cd not like 'OTH%' 
                                 and ((channel='DC' and cc.internet_typ_id in (100001)) or (channel<>'DC' and cc.internet_typ_id in (100002)))
                                 order by cc.internet_typ_id)
              ---added channel level email end
          else (select  top 1 party_email
						from party_contract x with (NOLOCK) 
						inner join party_contract_manu pcm with (NOLOCK) on pcm.contract_id=x.contract_id
						inner join party_role_internet bi with (NOLOCK) on x.party_role_id=bi.party_role_id and bi.is_deleted_ind='N'
						inner join party_internet c with (NOLOCK) on bi.party_internet_id=c.party_internet_id and c.is_deleted_ind='N' and  internet_cd not like 'OTH%'
						inner join adm_channel y on pcm.channel_id=y.stage_channel_id 
						WHERE ((channel='DC' and c.internet_typ_id in (100001)) or (channel<>'DC' and c.internet_typ_id in (100002)))
						and x.CONTRACT_ID=(select top 1 parent_contract_id from parent_level_v where contract_id=a.contract_id and level_id=b.email_level_id--order by level_depth
	)) end)party_email	--'Address Line'
    
from party_contract a with (NOLOCK)   
inner join party_contract_manu c with (NOLOCK) on a.contract_id=c.contract_id and c.is_deleted_ind='N' and c.is_set_up_cmpltd_ind='N'  
inner join card_level_contract_view b on a.contract_id=b.contract_id  
where a.is_deleted_ind='N';


-- dbo.trans_bus_card_rule_info_v_addr_email source

CREATE VIEW [trans_bus_card_rule_info_v_addr_email]
AS
SELECT  c.party_id AS partyid, a.contract_id AS contractid, c.contract_code, b.address_level_id AS bus_card_level, c.level_id AS contract_level, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 addr_typ_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 addr_typ_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 addr_typ_id
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 addr_typ_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS addr_typ_id,
                          (SELECT     TOP (1) y.addr_line3
                            FROM          dbo.party_role_addr AS x WITH (NOLOCK) INNER JOIN
                                                   dbo.party_addr AS y WITH (NOLOCK) ON x.party_addr_id = y.party_addr_id
                            WHERE      (x.party_role_id = a.party_role_id) AND (y.addr_id NOT LIKE 'HM%') AND (x.is_deleted_ind = 'N')) AS mailing_address, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 addr_line1
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 addr_line1
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 addr_line1
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 addr_line1
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS addr_line1, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                 (SELECT     TOP 1 addr_line2
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 addr_line2
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 addr_line2
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 addr_line2
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS addr_line2, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 city
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 city
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 city
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 city
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS city, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 country_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 country_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 country_id
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 country_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS country_id, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 state_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 state_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 state_id
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 state_id
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS state_id, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 other_state
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 other_state
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 other_state
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 other_state
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS other_state, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 postal_cd
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 postal_cd
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 postal_cd
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 postal_cd
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS postal_cd, 
                      (CASE WHEN b.address_level_id = c.level_id THEN
                          (SELECT     TOP 1 bad_addr_ind
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id > c.level_id THEN
                          (SELECT     TOP 1 bad_addr_ind
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id = a.contract_id) WHEN b.address_level_id = 100002 THEN
                          (SELECT     TOP 1 bad_addr_ind
                            FROM          party_addr a WITH (NOLOCK) INNER JOIN
                                                   adm_channel y ON y.stage_channel_id = c.channel_id
                            WHERE      ((channel = 'DC' AND a.addr_typ_id IN (100004)) OR
                                                   (channel <> 'DC' AND a.addr_typ_id IN (100001, 100003))) AND a.party_id = c.channel_id AND a.is_deleted_ind = 'N'
                            ORDER BY a.addr_typ_id) ELSE
                          (SELECT     TOP 1 bad_addr_ind
                            FROM          bus_address_v x WITH (NOLOCK)
                            WHERE      x.contract_id =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v WITH (NOLOCK)
                                                         WHERE      contract_id = a.contract_id AND level_id = b.address_level_id)) END) AS bad_addr_ind, 
                      (CASE WHEN b.email_level_id = c.level_id THEN
                          (SELECT     TOP 1 internet_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON b.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID = a.contract_id) 
                      WHEN b.email_level_id > c.level_id THEN
                          (SELECT     TOP 1 internet_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON b.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID = a.contract_id) 
                      WHEN b.email_level_id = 100002 THEN
                          (SELECT     TOP 1 cc.internet_typ_id
                            FROM          party_internet cc WITH (NOLOCK) INNER JOIN
                                                   adm_channel yy ON yy.stage_channel_id = c.channel_id
                            WHERE      cc.party_id = c.channel_id AND cc.is_deleted_ind = 'N' AND cc.internet_cd NOT LIKE 'OTH%' AND ((channel = 'DC' AND 
                                                   cc.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND cc.internet_typ_id IN (100002)))
                            ORDER BY cc.internet_typ_id) ELSE
                          (SELECT     TOP 1 internet_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet bi WITH (NOLOCK) ON x.party_role_id = bi.party_role_id AND bi.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON bi.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.email_level_id)) END) AS internet_typ_id, 
                      (CASE WHEN b.email_level_id = c.level_id THEN
                          (SELECT     TOP 1 party_email
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON b.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID = a.contract_id) 
                      WHEN b.email_level_id > c.level_id THEN
                          (SELECT     TOP 1 party_email
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON b.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID = a.contract_id) 
                      WHEN b.email_level_id = 100002 THEN
                          (SELECT     TOP 1 cc.party_email
                            FROM          party_internet cc WITH (NOLOCK) INNER JOIN
                                                   adm_channel yy ON yy.stage_channel_id = c.channel_id
                            WHERE      cc.party_id = c.channel_id AND cc.is_deleted_ind = 'N' AND cc.internet_cd NOT LIKE 'OTH%' AND ((channel = 'DC' AND 
                                                   cc.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND cc.internet_typ_id IN (100002)))
                            ORDER BY cc.internet_typ_id) ELSE
                          (SELECT     TOP 1 party_email
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_internet bi WITH (NOLOCK) ON x.party_role_id = bi.party_role_id AND bi.is_deleted_ind = 'N' INNER JOIN
                                                   party_internet c WITH (NOLOCK) ON bi.party_internet_id = c.party_internet_id AND c.is_deleted_ind = 'N' AND 
                                                   internet_cd NOT LIKE 'OTH%' INNER JOIN
                                                   adm_channel y ON pcm.channel_id = y.stage_channel_id
                            WHERE      ((channel = 'DC' AND c.internet_typ_id IN (100001)) OR
                                                   (channel <> 'DC' AND c.internet_typ_id IN (100002))) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.email_level_id)) END) AS party_email
FROM         dbo.party_contract AS a WITH (NOLOCK) INNER JOIN
              dbo.party_contract_manu AS c WITH (NOLOCK) ON a.contract_id = c.contract_id AND c.is_deleted_ind = 'N' AND 
                      c.is_set_up_cmpltd_ind = 'N' INNER JOIN
                      dbo.card_level_contract_view AS b ON a.contract_id = b.contract_id
WHERE     (a.is_deleted_ind = 'N');


-- dbo.trans_bus_card_rule_info_v_phn_fax source

CREATE VIEW [dbo].[trans_bus_card_rule_info_v_phn_fax]
AS
SELECT     c.party_id AS partyid, a.contract_id AS contractid, c.contract_code, b.address_level_id AS bus_card_level, c.level_id AS contract_level, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_loc_id
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_loc_id
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_loc_id
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_loc_id
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.phn_loc_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) ELSE
                          (SELECT     TOP 1 c.phn_loc_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID = a.contract_id) END) AS phn_loc_id, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_typ_id
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_typ_id
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_typ_id
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_typ_id
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.phn_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) ELSE
                          (SELECT     TOP 1 c.phn_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID = a.contract_id) END) AS phn_typ_id, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 country_cd
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 country_cd
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 country_cd
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 country_cd
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, country_cd
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, country_cd
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.country_cd
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) ELSE
                          (SELECT     TOP 1 c.country_cd
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID = a.contract_id) END) AS country_cd, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 area_cd
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 area_cd
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 area_cd
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 area_cd
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, area_cd
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, area_cd
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.area_cd
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) ELSE
                          (SELECT     TOP 1 c.area_cd
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID = a.contract_id) END) AS area_cd, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_num
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_num
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_num
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_num
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, phn_num
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, phn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
                          (SELECT     TOP 1 c.phn_num
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) END) AS phn_num, 
                      (CASE WHEN b.phone_level_id = c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id > c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          phn_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.phone_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005, 100006)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100006) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100001, 100002, 100005) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
                          (SELECT     TOP 1 c.extn_num
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100001, 100002, 100005, 100006) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.phone_level_id)) END) AS extn_num, 
                      (CASE WHEN b.fax_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_loc_id
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_loc_id
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_loc_id
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004, 100007)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_loc_id
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100007) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.phn_loc_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                 party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) ELSE
                          (SELECT     TOP 1 c.phn_loc_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID = a.contract_id) END) AS fax_loc_id, 
                      (CASE WHEN b.fax_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_typ_id
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_typ_id
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_typ_id
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004, 100007)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_typ_id
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100007) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) WHEN
                          (SELECT     TOP 1 parent_contract_id
                            FROM          parent_level_v
                            WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id) IS NOT NULL THEN
                          (SELECT     TOP 1 c.phn_typ_id
                         FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                                                         FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) ELSE
                          (SELECT     TOP 1 c.phn_typ_id
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn b WITH (NOLOCK) ON x.party_role_id = b.party_role_id AND b.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON b.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID = a.contract_id) END) AS fax_typ_id, 
                      (CASE WHEN b.fax_level_id = c.level_id THEN
                          (SELECT     TOP 1 phn_num
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id > c.level_id THEN
                          (SELECT     TOP 1 phn_num
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 phn_num
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004, 100007)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 phn_num
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, phn_num
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100007) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, phn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
			    (SELECT     TOP 1 c.phn_num
	    FROM          party_contract x WITH (NOLOCK) INNER JOIN
				   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
				   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
				   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
	    WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
				       (SELECT     TOP 1 parent_contract_id
					 FROM          parent_level_v
					 WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) END) AS fax_num, 
                      (CASE WHEN b.fax_level_id = c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id > c.level_id THEN
                          (SELECT     TOP 1 extn_num
                            FROM          fax_priority_v x
                            WHERE      x.CONTRACT_ID = a.contract_id) WHEN b.fax_level_id = 100002 THEN
                          (SELECT     (CASE WHEN ac.channel <> 'DC' THEN
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          party_phn f WITH (NOLOCK)
                                                         WHERE      f.party_id = cv.channel_id AND f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004, 100007)
                                                         ORDER BY phn_typ_id, phn_loc_id) ELSE
                                                       (SELECT     TOP 1 extn_num
                                                         FROM          (SELECT     f.phn_typ_id, 1 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM          party_phn f WITH (NOLOCK)
                                                                                 WHERE      f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100007) AND f.party_id = cv.channel_id
                                                                                 UNION
                                                                                 SELECT     f.phn_typ_id, 2 SNO, party_phn_id, phn_loc_id, extn_num
                                                                                 FROM         party_phn f WITH (NOLOCK)
                                                                                 WHERE     f.is_deleted_ind = 'N' AND f.phn_typ_id IN (100003, 100004) AND f.party_id = cv.channel_id) AA
                                                         ORDER BY SNO, phn_loc_id) END) phn_loc_id
                            FROM          channel_view cv INNER JOIN
                                                   adm_channel ac ON cv.channel_id = ac.stage_channel_id
                            WHERE      cv.channel_id = C.channel_id) ELSE
                          (SELECT     TOP 1 c.extn_num
                            FROM          party_contract x WITH (NOLOCK) INNER JOIN
                                                   party_contract_manu pcm WITH (NOLOCK) ON pcm.contract_id = x.contract_id INNER JOIN
                                                   party_role_phn bp WITH (NOLOCK) ON x.party_role_id = bp.party_role_id AND bp.is_deleted_ind = 'N' INNER JOIN
                                                   party_phn c WITH (NOLOCK) ON bp.party_phn_id = c.party_phn_id AND c.is_deleted_ind = 'N'
                            WHERE      c.phn_typ_id IN (100003, 100004, 100007) AND x.CONTRACT_ID =
                                                       (SELECT     TOP 1 parent_contract_id
                          FROM          parent_level_v
                                                         WHERE      contract_id = a.contract_id AND level_id = b.fax_level_id)) END) AS fax_extn_num
FROM         dbo.party_contract AS a WITH (NOLOCK) INNER JOIN
                      dbo.party_contract_manu AS c WITH (NOLOCK) ON a.contract_id = c.contract_id AND c.is_deleted_ind = 'N' AND 
                      c.is_set_up_cmpltd_ind = 'N' INNER JOIN
                      dbo.card_level_contract_view AS b ON a.contract_id = b.contract_id
WHERE     (a.is_deleted_ind = 'N');


-- dbo.userrole_v source

CREATE VIEW [userrole_v] AS 
select role_cd as role_cd, sl_role_dsc as role_desc from userrole;


-- dbo.vRandNumber source

CREATE VIEW [dbo].[vRandNumber] AS SELECT RAND() as RandNumber;


-- dbo.vtemp source

CREATE VIEW [vtemp] as select filter_name,action_date from dbo.rep_audit_history;